// 3. CREATOR LOGIN
// POST /api/creator/login
// Body: { email, password }
// ════════════════════════════════════════════════════════════
app.post('/api/creator/login', async (req, res) => {
  // Hard timeout to prevent infinite hangs
  const timer = setTimeout(() => {
    if (!res.headersSent) res.status(504).json({ error: 'Login timed out — please try again' });
  }, 12000);
  try {
    const { email, password } = req.body;
    if (!email || !password) {
      clearTimeout(timer);
      return res.status(400).json({ error: 'Missing email or password' });
    }

    // Use direct Postgres if available (bypasses Cloudflare), fall back to Supabase client
    let user, settings;
    if (pool) {
      const users = await dbQuery(
        'SELECT id, email, display_name, password_hash, is_creator FROM users WHERE email = $1 AND is_creator = true LIMIT 1',
        [email.toLowerCase()]
      );
      user = users[0] || null;
    } else {
      const { data, error: userErr } = await supabase
        .from('users')
        .select('id, email, display_name, password_hash, is_creator')
        .eq('email', email.toLowerCase())
        .eq('is_creator', true)
        .maybeSingle();
      if (userErr) { console.error('[login] DB error:', userErr.message); clearTimeout(timer); return res.status(500).json({ error: 'Database error' }); }
      user = data;
    }

    if (!user) { clearTimeout(timer); return res.status(401).json({ error: 'Invalid credentials' }); }

    const valid = await bcrypt.compare(password, user.password_hash);
    if (!valid) { clearTimeout(timer); return res.status(401).json({ error: 'Invalid credentials' }); }

    if (pool) {
      const settingsRows = await dbQuery(
        'SELECT slug, custom_points_name, primary_color FROM creator_settings WHERE creator_id = $1 LIMIT 1',
        [user.id]
      );
      settings = settingsRows[0] || null;
    } else {
      const { data } = await supabase
        .from('creator_settings')
        .select('slug, custom_points_name, primary_color')
        .eq('creator_id', user.id)
        .maybeSingle();
      settings = data;
    }

    const token = makeToken({ id: user.id, email: user.email, slug: settings?.slug });

    clearTimeout(timer);
    if (!res.headersSent) {
      res.json({
        token,
        user: {
          id: user.id,
          email: user.email,
          display_name: user.display_name,
          slug: settings?.slug,
          custom_points_name: settings?.custom_points_name,
          primary_color: settings?.primary_color
        }
      });
    }

  } catch (err) {
    clearTimeout(timer);
    console.error('creator login error:', err);
    if (!res.headersSent) res.status(500).json({ error: err.message });
  }
});

// ════════════════════════════════════════════════════════════
// PASSWORD RESET — forgot + reset + admin-trigger
// ════════════════════════════════════════════════════════════
app.post('/api/auth/forgot-password', async (req, res) => {
  const ip = req.ip || req.headers['x-forwarded-for'] || 'unknown';
  if (!rateLimit('forgot-pw', ip, 3, 300000)) return res.status(429).json({ error: 'Too many reset requests. Try again in 5 minutes.' });
  try {
    const { email } = req.body || {};
    if (!email) return res.status(400).json({ error: 'Email required' });
    const token = require('crypto').randomBytes(32).toString('hex');
    const expires = new Date(Date.now() + 60 * 60 * 1000).toISOString();

    // Ensure columns exist (safe to call repeatedly)
    await dbQuery('ALTER TABLE creator_settings ADD COLUMN IF NOT EXISTS password_reset_token TEXT').catch(() => {});
    await dbQuery('ALTER TABLE creator_settings ADD COLUMN IF NOT EXISTS password_reset_expires TIMESTAMPTZ').catch(() => {});

    const rows = await dbQuery('SELECT id, display_name, email FROM creator_settings WHERE LOWER(email) = $1 LIMIT 1', [email.toLowerCase().trim()]);
    if (rows[0]) {
      await dbQuery('UPDATE creator_settings SET password_reset_token = $1, password_reset_expires = $2 WHERE id = $3', [token, expires, rows[0].id]);
      _sendResetEmail(email, rows[0].display_name || 'there', token);
    }

    // Always return ok — don't reveal whether email exists
    res.json({ ok: true });
  } catch (err) {
    console.error('[forgot-password]', err.message, err.stack);
    res.status(500).json({ error: 'Something went wrong' });
  }
});

app.post('/api/auth/reset-password', async (req, res) => {
  try {
    const { token, password } = req.body || {};
    if (!token || !password) return res.status(400).json({ error: 'Token and password required' });
    if (password.length < 8) return res.status(400).json({ error: 'Password must be at least 8 characters' });

    const now = new Date().toISOString();
    const password_hash = await bcrypt.hash(password, 10);

    const rows = await dbQuery('SELECT id FROM creator_settings WHERE password_reset_token = $1 AND password_reset_expires > $2 LIMIT 1', [token, now]);
    if (rows[0]) {
      await dbQuery('UPDATE creator_settings SET password_hash = $1, password_reset_token = NULL, password_reset_expires = NULL WHERE id = $2', [password_hash, rows[0].id]);
      return res.json({ ok: true });
    }

    res.status(400).json({ error: 'Reset link is invalid or has expired' });
  } catch (err) {
    console.error('[reset-password]', err.message);
    res.status(500).json({ error: 'Something went wrong' });
  }
});

app.post('/api/admin/reset-password', async (req, res) => {
  const ip = req.ip || req.headers['x-forwarded-for'] || 'unknown';
  if (!rateLimit('admin-secret', ip, 10, 3600000)) {
    console.warn('[security] Admin secret brute force attempt from', ip);
    return res.status(429).json({ error: 'Too many attempts' });
  }
  const secret = req.headers['x-admin-secret'];
  if (secret !== process.env.ADMIN_SECRET) return res.status(403).json({ error: 'Forbidden' });
  try {
    const { email } = req.body || {};
    if (!email) return res.status(400).json({ error: 'Email required' });
    const token = require('crypto').randomBytes(32).toString('hex');
    const expires = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(); // 24h for admin

    const rows = await dbQuery('SELECT id, display_name FROM creator_settings WHERE LOWER(email) = $1 LIMIT 1', [email.toLowerCase().trim()]);
    if (!rows[0]) return res.status(404).json({ error: 'No account found with that email' });
    await dbQuery('UPDATE creator_settings SET password_reset_token = $1, password_reset_expires = $2 WHERE id = $3', [token, expires, rows[0].id]);
    _sendResetEmail(email, rows[0].display_name || 'there', token);
    res.json({ ok: true, sent_to: email });
  } catch (err) {
    console.error('[admin-reset-password]', err.message);
    res.status(500).json({ error: 'Something went wrong' });
  }
});

function _sendResetEmail(toEmail, name, token) {
  try {
    const transporter = createMailTransport();
    if (!transporter) { console.warn('[reset-email] No SMTP configured — SMTP_HOST not set'); return; }
    const resetUrl = `https://hyperflex.network/reset-password?token=${token}`;
    console.log('[reset-email] Attempting to send to', toEmail, 'via', process.env.SMTP_HOST);
    transporter.sendMail({
      from: process.env.SMTP_FROM || 'HYPERFLEX <noreply@hyperflex.network>',
      to: toEmail,
      subject: 'Reset your HYPERFLEX password',
      html: `<div style="background:#0e0e0c;color:#f0ebe3;font-family:sans-serif;max-width:520px;margin:0 auto;padding:32px;border-radius:10px;">
        <div style="font-size:22px;font-weight:800;margin-bottom:8px;"><span style="color:#c9920d;">HYPER</span>FLEX</div>
        <h2 style="font-size:18px;margin:24px 0 8px;">Reset your password</h2>
        <p style="color:#aaa;font-size:14px;line-height:1.6;margin-bottom:24px;">Hey ${name}, click below to reset your password. This link expires in 1 hour.</p>
        <a href="${resetUrl}" style="display:inline-block;background:#c9920d;color:#0e0e0c;font-weight:700;padding:13px 28px;border-radius:6px;text-decoration:none;font-size:15px;">Reset Password &rarr;</a>
        <p style="color:#555;font-size:12px;margin-top:28px;">If you didn't request this, ignore this email.<br/>Link: ${resetUrl}</p>
      </div>`
    }).then(info => {
      console.log('[reset-email] SENT to', toEmail, 'messageId:', info.messageId);
    }).catch(e => console.error('[reset-email] FAILED:', e.message));
  } catch(e) { console.error('[reset-email] ERROR:', e.message); }
}

