app.post('/api/creator/announcements', requireCreator, async (req, res) => {
  try {
    let settings;
    if (pool) {
      const rows = await dbQuery('SELECT slug FROM creator_settings WHERE creator_id = $1 LIMIT 1', [req.creator.id]);
      settings = rows[0] || null;
    } else {
      const { data: d } = await supabase.from('creator_settings').select('slug').eq('creator_id', req.creator.id).single();
      settings = d;
    }
    const { title, body, pinned } = req.body;
    if (!title || !title.trim()) return res.status(400).json({ error: 'Title required.' });
    let data, error;
    if (pool) {
      try {
        const rows = await dbQuery('INSERT INTO creator_announcements (creator_slug, title, body, pinned) VALUES ($1, $2, $3, $4) RETURNING *', [settings.slug, title.trim().slice(0,200), (body||'').trim().slice(0,1000), !!pinned]);
        data = rows[0];
      } catch (e) { error = e; }
    } else {
      let d, e;
      if (pool) {
        const _insData = Array.isArray({ creator_slug: settings.slug, title: title.trim().slice(0,200), body: (body||'').trim().slice(0,1000), pinned: !!pinned }) ? ({ creator_slug: settings.slug, title: title.trim().slice(0,200), body: (body||'').trim().slice(0,1000), pinned: !!pinned })[0] : ({ creator_slug: settings.slug, title: title.trim().slice(0,200), body: (body||'').trim().slice(0,1000), pinned: !!pinned });
        const _cols = Object.keys(_insData); const _vals = Object.values(_insData);
        const _phs = _cols.map((_, i) => `$${i + 1}`).join(', ');
        const _rows = await dbQuery(`INSERT INTO creator_announcements (${_cols.join(', ')}) VALUES (${_phs}) RETURNING *`, _vals);
        d = _rows[0] || null;
      } else {
        const { data: d, error: e } = await supabase.from('creator_announcements') .insert({ creator_slug: settings.slug, title: title.trim().slice(0,200), body: (body||'').trim().slice(0,1000), pinned: !!pinned }) .select().single();
      }
      data = d; error = e;
    }
    if (error) throw error;
    res.json({ ok: true, announcement: data });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// ── COMMUNITY ACCURACY / CROWD WISDOM SCORE ─────────────────────────────
// Measures how good this community is at predicting outcomes
app.get('/api/community/:slug/accuracy', async (req, res) => {
  try {
    const { slug } = req.params;

    // Get all resolved markets for this community
    const resolved = await dbQuery(`
      SELECT id, question, category, outcome, yes_votes, no_votes, trader_count,
             resolved_at, created_at, expiry_date
      FROM markets
      WHERE tenant_slug = $1 AND outcome IS NOT NULL
      ORDER BY resolved_at DESC
    `, [slug]);

    if (!resolved || !resolved.length) {
      return res.json({
        slug,
        total_resolved: 0,
        correct: 0,
        wrong: 0,
        accuracy_pct: null,
        vs_random: null,
        best_call: null,
        worst_call: null,
        by_category: {},
        recent: [],
        message: 'No markets resolved yet. Accuracy tracking begins when markets close.'
      });
    }

    let correct = 0;
    let wrong = 0;
    let totalConfidence = 0;
    const byCategory = {};
    const calls = [];

    for (const m of resolved) {
      const yesVotes = parseInt(m.yes_votes) || 0;
      const noVotes = parseInt(m.no_votes) || 0;
      const totalVotes = yesVotes + noVotes;
      if (totalVotes < 2) continue; // need at least 2 votes to count

      const communityPct = Math.round(yesVotes / totalVotes * 100);
      const communitySide = communityPct >= 50 ? 'YES' : 'NO';
      const communityConfidence = Math.abs(communityPct - 50); // 0-50, higher = more confident
      const actualOutcome = (m.outcome || '').toUpperCase();
      const wasCorrect = communitySide === actualOutcome;

      if (wasCorrect) correct++;
      else wrong++;
      totalConfidence += communityConfidence;

      // Category tracking
      const cat = m.category || 'other';
      if (!byCategory[cat]) byCategory[cat] = { correct: 0, wrong: 0, total: 0 };
      byCategory[cat].total++;
      if (wasCorrect) byCategory[cat].correct++;
      else byCategory[cat].wrong++;

      calls.push({
        market_id: m.id,
        question: m.question,
        category: cat,
        community_said: communitySide,
        community_pct: communityPct,
        confidence: communityConfidence,
        actual_outcome: actualOutcome,
        correct: wasCorrect,
        traders: parseInt(m.trader_count) || 0,
        resolved_at: m.resolved_at
      });
    }

    const totalJudged = correct + wrong;
    const accuracyPct = totalJudged > 0 ? Math.round(correct / totalJudged * 1000) / 10 : null;
    const vsRandom = accuracyPct != null ? Math.round((accuracyPct - 50) * 10) / 10 : null;
    const avgConfidence = totalJudged > 0 ? Math.round(totalConfidence / totalJudged) : 0;

    // Best and worst calls (by confidence * correctness)
    const correctCalls = calls.filter(c => c.correct).sort((a, b) => b.confidence - a.confidence);
    const wrongCalls = calls.filter(c => !c.correct).sort((a, b) => b.confidence - a.confidence);

    // Category accuracy
    const categoryAccuracy = {};
    for (const [cat, data] of Object.entries(byCategory)) {
      categoryAccuracy[cat] = {
        total: data.total,
        correct: data.correct,
        accuracy_pct: data.total > 0 ? Math.round(data.correct / data.total * 1000) / 10 : null
      };
    }

    // Calibration: when community says 70%, how often are they right?
    const calibration = {};
    for (const c of calls) {
      const bucket = Math.round(c.community_pct / 10) * 10; // 10%, 20%, ... 90%
      if (!calibration[bucket]) calibration[bucket] = { predicted: 0, actual: 0 };
      calibration[bucket].predicted++;
      if ((c.community_said === 'YES' && c.correct) || (c.community_said === 'NO' && c.correct)) {
        calibration[bucket].actual++;
      }
    }

    // Grade
    let grade, gradeColor;
    if (accuracyPct === null) { grade = '—'; gradeColor = '#7a7870'; }
    else if (accuracyPct >= 70) { grade = 'A'; gradeColor = '#22c55e'; }
    else if (accuracyPct >= 60) { grade = 'B'; gradeColor = '#c9920d'; }
    else if (accuracyPct >= 50) { grade = 'C'; gradeColor = '#f59e0b'; }
    else { grade = 'D'; gradeColor = '#ef4444'; }

    res.json({
      slug,
      total_resolved: totalJudged,
      correct,
      wrong,
      accuracy_pct: accuracyPct,
      vs_random: vsRandom,
      avg_confidence: avgConfidence,
      grade,
      grade_color: gradeColor,
      best_call: correctCalls[0] || null,
      worst_call: wrongCalls[0] || null,
      by_category: categoryAccuracy,
      calibration,
      recent: calls.slice(0, 20)
    });
  } catch (err) {
    console.error('[community-accuracy]', err.message);
    res.json({ slug: req.params.slug, total_resolved: 0, accuracy_pct: null, message: 'Accuracy data unavailable' });
  }
});

// ── FACT-CHECK ENGINE ────────────────────────────────────────────────────
// Submit a claim (tweet, headline, prediction) → AI extracts the testable
// assertion → matches against live Polymarket data → scores it
app.post('/api/fact-check', async (req, res) => {
  try {
    const { claim, source_url, source_author } = req.body || {};
    if (!claim || claim.length < 10) return res.status(400).json({ error: 'Claim must be at least 10 characters' });
    if (!process.env.ANTHROPIC_API_KEY) return res.json({ verdict: null, error: 'AI not configured' });

    // Rate limit
    const ip = req.ip || 'unknown';
    const now = Date.now();
    if (!_factCheckRL) _factCheckRL = new Map();
    let rl = _factCheckRL.get(ip);
    if (!rl || now > rl.resetAt) rl = { count: 0, resetAt: now + 60000 };
    if (rl.count >= 5) return res.status(429).json({ error: 'Rate limited. Try again in a minute.' });
    rl.count++;
    _factCheckRL.set(ip, rl);

    // Get current market data for context
    const screenerMkts = _screenerCache && Array.isArray(_screenerCache.data) ? _screenerCache.data : [];
    const marketContext = screenerMkts.slice(0, 30).map(m => {
      const price = m.yes_price != null ? Math.round(m.yes_price * 100) : '?';
      return `"${(m.question || '').substring(0, 80)}" — ${price}% YES`;
    }).join('\n');

    // Ask Claude to fact-check the claim against market data
    const resp = await anthropic.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 800,
      messages: [{
        role: 'user',
        content: `You are a prediction market fact-checker. Analyze this claim and score it.

CLAIM: "${claim}"
${source_author ? `SOURCE: ${source_author}` : ''}
${source_url ? `URL: ${source_url}` : ''}

CURRENT POLYMARKET DATA (live odds on real events):
${marketContext || 'No market data available'}

Respond in this exact JSON format:
{
  "testable_assertion": "The specific factual claim being made",
  "verdict": "LIKELY TRUE" or "LIKELY FALSE" or "MIXED" or "UNVERIFIABLE",
  "confidence": 1-100,
  "reasoning": "2-3 sentence explanation of why, referencing market data where relevant",
  "related_market": "The most relevant Polymarket question if one exists, or null",
  "market_odds": "What the market currently says (e.g. '73% YES') or null",
  "edge_vs_market": "If the claim disagrees with the market, explain the gap"
}

Only respond with the JSON object, nothing else.`
      }]
    });

    const text = (resp.content[0]?.text || '').trim();
    let result;
    try {
      // Extract JSON from response (handle markdown code blocks)
      const jsonStr = text.replace(/^```json?\n?/, '').replace(/\n?```$/, '').trim();
      result = JSON.parse(jsonStr);
    } catch(e) {
      result = { verdict: 'UNVERIFIABLE', confidence: 30, reasoning: text.substring(0, 300), testable_assertion: claim };
    }

    // Color coding
    const verdictColors = { 'LIKELY TRUE': '#22c55e', 'LIKELY FALSE': '#ef4444', 'MIXED': '#f59e0b', 'UNVERIFIABLE': '#7a7870' };
    result.verdict_color = verdictColors[result.verdict] || '#7a7870';

    // Log to DB for tracking
    await dbQuery(`CREATE TABLE IF NOT EXISTS fact_checks (
      id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text,
      claim TEXT, source_url TEXT, source_author TEXT,
      verdict TEXT, confidence INTEGER, reasoning TEXT,
      related_market TEXT, market_odds TEXT,
      created_at TIMESTAMPTZ DEFAULT NOW()
    )`).catch(() => {});
    await dbQuery('INSERT INTO fact_checks (claim, source_url, source_author, verdict, confidence, reasoning, related_market, market_odds) VALUES ($1,$2,$3,$4,$5,$6,$7,$8)',
      [claim, source_url || null, source_author || null, result.verdict, result.confidence, result.reasoning, result.related_market || null, result.market_odds || null]
    ).catch(() => {});

    res.json(result);
  } catch(err) {
    console.error('[fact-check]', err.message);
    res.json({ verdict: 'ERROR', confidence: 0, reasoning: 'Fact-check temporarily unavailable.', verdict_color: '#7a7870' });
  }
});
let _factCheckRL = new Map();

// Get recent fact-checks (public)
