// GET /api/predictors — top predictors leaderboard
app.get('/api/predictors', async (req, res) => {
  try {
    const { sort = 'win_rate', q = '', limit = 100 } = req.query;
    const lim = Math.min(parseInt(limit) || 100, 200);

    // Aggregate settled positions per user (limit to 5000 for perf)
    let rows;
    if (pool) {
      rows = await dbQuery('SELECT user_id, amount, potential_payout, settled, won, created_at FROM positions WHERE settled = true LIMIT 5000');
    } else {
      const { data, error } = await supabase
        .from('positions')
        .select('user_id, amount, potential_payout, settled, won, created_at')
        .eq('settled', true)
        .limit(5000);
      if (error) throw error;
      rows = data;
    }

    if (!rows || !rows.length) return res.json([]);

    // Group by user_id
    const byUser = {};
    for (const pos of rows || []) {
      if (!byUser[pos.user_id]) byUser[pos.user_id] = { wins: 0, total: 0, pnl: 0, lastWon: false, streak: 0, streakArr: [] };
      const u = byUser[pos.user_id];
      u.total++;
      if (pos.won) { u.wins++; u.pnl += (pos.potential_payout || 0) - (pos.amount || 0); }
      else { u.pnl -= (pos.amount || 0); }
      u.streakArr.push({ won: pos.won, ts: pos.created_at });
    }

    // Filter users with ≥3 settled predictions
    const userIds = Object.keys(byUser).filter(uid => byUser[uid].total >= 3);
    if (!userIds.length) return res.json([]);

    // Calculate streaks (consecutive wins from most recent)
    for (const uid of userIds) {
      const u = byUser[uid];
      u.streakArr.sort((a, b) => new Date(b.ts) - new Date(a.ts));
      let streak = 0;
      for (const p of u.streakArr) { if (p.won) streak++; else break; }
      u.streak = streak;
    }

    // Fetch display names
    let userRows;
    if (pool) {
      userRows = await dbQuery('SELECT id, display_name FROM users WHERE id = ANY($1)', [userIds]);
    } else {
      const { data } = await supabase.from('users').select('id, display_name').in('id', userIds);
      userRows = data;
    }

    const nameMap = {};
    for (const u of userRows || []) nameMap[u.id] = u.display_name;

    // Check polymarket connections (users table)
    let csRows;
    if (pool) {
      csRows = await dbQuery('SELECT id, polymarket_address FROM users WHERE id = ANY($1) AND polymarket_address IS NOT NULL', [userIds]);
    } else {
      const { data } = await supabase.from('users').select('id, polymarket_address').in('id', userIds).not('polymarket_address', 'is', null);
      csRows = data;
    }

    const polyMap = {};
    for (const cs of csRows || []) polyMap[cs.id] = cs.polymarket_address;

    // Build result
    let result = userIds.map(uid => {
      const u = byUser[uid];
      const win_rate = u.total > 0 ? Math.round((u.wins / u.total) * 100) : 0;
      const platforms = ['HFX'];
      if (polyMap[uid]) platforms.push('POLY');
      return {
        user_id: uid,
        display_name: nameMap[uid] || 'Anonymous',
        win_rate,
        total_predictions: u.total,
        streak: u.streak,
        pnl_pts: Math.round(u.pnl / 100), // centpoints → pts
        polymarket_address: polyMap[uid] || null,
        platforms
      };
    });

    // Search filter
    if (q) {
      const ql = q.toLowerCase();
      result = result.filter(r => r.display_name.toLowerCase().includes(ql));
    }

    // Sort
    const sortFns = {
      win_rate: (a, b) => b.win_rate - a.win_rate,
      predictions: (a, b) => b.total_predictions - a.total_predictions,
      streak: (a, b) => b.streak - a.streak,
      pnl: (a, b) => b.pnl_pts - a.pnl_pts
    };
    result.sort(sortFns[sort] || sortFns.win_rate);

    res.json(result.slice(0, lim));
  } catch (err) {
    console.error('[api/predictors]', err);
    res.status(500).json({ error: 'Failed to load predictors' });
  }
});

// ── LEADERBOARD API ────────────────────────────────
// GET /api/leaderboard?period=30d — shows TOP POLYMARKET TRADERS from Polymarket leaderboard API
// Falls back to HFX community leaderboard if Polymarket API fails
// Cached 5 minutes
const _leaderboardCache = {};

async function fetchPolymarketLeaderboard(period) {
  const windowMap = { '7d': 'day', '30d': 'week', 'all': 'all' };
  const window = windowMap[period] || 'week';
  const url = `https://data-api.polymarket.com/v1/leaderboard?limit=50&window=${window}`;
  const resp = await fetch(url, { headers: { 'Accept': 'application/json' }, signal: AbortSignal.timeout(8000) });
  if (!resp.ok) throw new Error(`Polymarket API returned ${resp.status}`);
  const traders = await resp.json();
  if (!Array.isArray(traders) || traders.length === 0) throw new Error('Empty Polymarket leaderboard response');
  return traders.map((t, i) => {
    const pnl = parseFloat(t.pnl) || 0;
    const vol = parseFloat(t.vol) || parseFloat(t.volume) || 0;
    const sharpScore = Math.min(100, Math.round(
      50 +
      (pnl > 100000 ? 30 : pnl > 10000 ? 20 : pnl > 1000 ? 10 : 0) +
      (vol > 100000 ? 15 : vol > 10000 ? 10 : 0)
    ));
    return {
      rank: i + 1,
      display_name: (() => { const n = t.userName || t.username || t.name || ''; if (n && !/^0x[0-9a-fA-F]{6,}/.test(n)) return n; const addr = t.proxyWallet || t.proxy_wallet || t.address || n || ''; return addr.length > 10 ? addr.slice(0, 6) + '...' + addr.slice(-4) : addr || `Trader #${i+1}`; })(),
      total_pnl: Math.round(pnl),
      volume: Math.round(vol),
      wallet: t.proxyWallet || t.proxy_wallet || t.address || '',
      win_rate: 0,
      sharp_score: sharpScore,
      platforms: ['POLY']
    };
  });
}

async function fetchHFXCommunityLeaderboard(p) {
  let dateFilter = null;
  if (p === '7d') dateFilter = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
  else if (p === '30d') dateFilter = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();

  let rows;
  if (pool) {
    if (dateFilter) {
      rows = await dbQuery('SELECT user_id, amount, potential_payout, won, created_at FROM positions WHERE settled = true AND created_at >= $1 LIMIT 10000', [dateFilter]);
    } else {
      rows = await dbQuery('SELECT user_id, amount, potential_payout, won, created_at FROM positions WHERE settled = true LIMIT 10000');
    }
  } else {
    let q = supabase.from('positions').select('user_id, amount, potential_payout, won, created_at').eq('settled', true);
    if (dateFilter) q = q.gte('created_at', dateFilter);
    const { data, error } = await q.limit(10000);
    if (error) throw error;
    rows = data;
  }
  if (!rows || !rows.length) return [];

  let cachedRows = [];
  try {
    if (pool) {
      if (dateFilter) {
        cachedRows = await dbQuery('SELECT user_id, platform, side, pnl, created_at FROM cached_positions WHERE created_at >= $1 LIMIT 10000', [dateFilter]);
      } else {
        cachedRows = await dbQuery('SELECT user_id, platform, side, pnl, created_at FROM cached_positions LIMIT 10000');
      }
    } else {
      let q2 = supabase.from('cached_positions').select('user_id, platform, side, pnl, created_at');
      if (dateFilter) q2 = q2.gte('created_at', dateFilter);
      const { data: d2 } = await q2.limit(10000);
      cachedRows = d2 || [];
    }
  } catch(e) { /* cached_positions may not exist yet */ }

  let manualBetRows = [];
  try {
    if (pool) {
      if (dateFilter) {
        manualBetRows = await dbQuery("SELECT user_id, platform, status, pnl, amount, created_at FROM manual_bets WHERE status IN ('won','lost','push','void') AND created_at >= $1 LIMIT 10000", [dateFilter]);
      } else {
        manualBetRows = await dbQuery("SELECT user_id, platform, status, pnl, amount, created_at FROM manual_bets WHERE status IN ('won','lost','push','void') LIMIT 10000");
      }
    } else {
      let q3 = supabase.from('manual_bets').select('user_id, platform, status, pnl, amount, created_at').in('status', ['won','lost','push','void']);
      if (dateFilter) q3 = q3.gte('created_at', dateFilter);
      const { data: d3 } = await q3.limit(10000);
      manualBetRows = d3 || [];
    }
  } catch(e) { /* manual_bets may not exist yet */ }

  const byUser = {};
  for (const pos of rows) {
    if (!byUser[pos.user_id]) byUser[pos.user_id] = { wins: 0, total: 0, pnl: 0, platforms: new Set(['HFX']) };
    const u = byUser[pos.user_id];
    u.total++;
    if (pos.won) { u.wins++; u.pnl += (pos.potential_payout || 0) - (pos.amount || 0); }
    else { u.pnl -= (pos.amount || 0); }
  }

  for (const cp of cachedRows) {
    if (!byUser[cp.user_id]) byUser[cp.user_id] = { wins: 0, total: 0, pnl: 0, platforms: new Set() };
    const u = byUser[cp.user_id];
    u.total++;
    if (cp.pnl > 0) u.wins++;
    u.pnl += (cp.pnl || 0);
    if (cp.platform) u.platforms.add(cp.platform.toUpperCase());
  }

  for (const mb of manualBetRows) {
    if (!byUser[mb.user_id]) byUser[mb.user_id] = { wins: 0, total: 0, pnl: 0, platforms: new Set() };
    const u = byUser[mb.user_id];
    u.total++;
    if (mb.status === 'won') u.wins++;
    u.pnl += ((parseFloat(mb.pnl) || 0) * 100);
    if (mb.platform) u.platforms.add(mb.platform.toUpperCase());
  }

  const userIds = Object.keys(byUser).filter(uid => byUser[uid].total >= 3);
  if (!userIds.length) return [];

  let userRows;
  if (pool) {
    userRows = await dbQuery('SELECT id, display_name, polymarket_address, kalshi_api_key, manifold_username FROM users WHERE id = ANY($1)', [userIds]);
  } else {
    const { data } = await supabase.from('users').select('id, display_name, polymarket_address, kalshi_api_key, manifold_username').in('id', userIds);
    userRows = data;
  }
  const userMap = {};
  for (const u of userRows || []) userMap[u.id] = u;

  let result = userIds.map(uid => {
    const u = byUser[uid];
    const info = userMap[uid] || {};
    const winRate = u.total > 0 ? (u.wins / u.total) * 100 : 0;
    const totalPnl = u.pnl / 100;
    const platforms = [...u.platforms];
    if (info.polymarket_address && !platforms.includes('POLY')) platforms.push('POLY');
    if (info.kalshi_api_key && !platforms.includes('KALSHI')) platforms.push('KALSHI');
    if (info.manifold_username && !platforms.includes('MANIFOLD')) platforms.push('MANIFOLD');

    const sharpScore = Math.min(100, Math.round(
      winRate * 0.8 +
      Math.min(20, u.total * 0.5) +
      (totalPnl > 0 ? 15 : 0) +
      (platforms.length > 1 ? 5 : 0)
    ));

    return {
      user_id: uid,
      display_name: info.display_name || 'Anonymous',
      win_rate: Math.round(winRate),
      total_pnl: Math.round(totalPnl),
      sharp_score: sharpScore,
      trade_count: u.total,
      platforms
    };
  });

  result.sort((a, b) => b.sharp_score - a.sharp_score);
  result = result.slice(0, 50);
  result.forEach((r, i) => { r.rank = i + 1; });
  return result;
}

app.get('/api/leaderboard', async (req, res) => {
  try {
    // If ?slug= is present, serve the community-specific leaderboard
    const communitySlug = req.query.slug || req.tenant?.subdomain || null;
    if (communitySlug) {
      const qs = new URLSearchParams(req.query).toString();
      return res.redirect(307, `/api/community-leaderboard?${qs}`);
    }

    // Global Polymarket leaderboard
    const period = (req.query.period || '30d').toLowerCase();
    const validPeriods = ['7d', '30d', 'all'];
    const p = validPeriods.includes(period) ? period : '30d';
    const cacheKey = `lb_${p}`;
    if (_leaderboardCache[cacheKey] && Date.now() - _leaderboardCache[cacheKey].ts < 5 * 60 * 1000) {
      return res.json(_leaderboardCache[cacheKey].data);
    }

    let result;
    try {
      // Primary: fetch top Polymarket traders from the Polymarket leaderboard API
      result = await fetchPolymarketLeaderboard(p);
      console.log(`[api/leaderboard] Fetched ${result.length} traders from Polymarket API (window=${p})`);
    } catch (polyErr) {
      // Fallback: use HFX community leaderboard if Polymarket API fails
      console.warn('[api/leaderboard] Polymarket API failed, falling back to HFX community:', polyErr.message);
      result = await fetchHFXCommunityLeaderboard(p);
    }

    _leaderboardCache[cacheKey] = { ts: Date.now(), data: result };
    res.json(result);
  } catch (err) {
    console.error('[api/leaderboard]', err);
    res.status(500).json({ error: 'Failed to load leaderboard' });
  }
});

// ── SHARP MONEY FEED ────────────────────────────────
// GET /api/sharp-money-feed?limit=5 — recent positions from sharp traders, cached 3 min
const _sharpMoneyFeedCache = { ts: 0, data: [] };
app.get('/api/sharp-money-feed', async (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit) || 5, 20);
    if (_sharpMoneyFeedCache.ts && Date.now() - _sharpMoneyFeedCache.ts < 3 * 60 * 1000) {
      return res.json(_sharpMoneyFeedCache.data.slice(0, limit));
    }

    let posRows;
    if (pool) {
      posRows = await dbQuery('SELECT user_id, won FROM positions WHERE settled = true LIMIT 10000');
    } else {
      const { data, error } = await supabase.from('positions').select('user_id, won').eq('settled', true).limit(10000);
      if (error) throw error;
      posRows = data;
    }

    const byUser = {};
    for (const pos of posRows || []) {
      if (!byUser[pos.user_id]) byUser[pos.user_id] = { wins: 0, total: 0 };
      byUser[pos.user_id].total++;
      if (pos.won) byUser[pos.user_id].wins++;
    }

    const sharpUserIds = Object.keys(byUser).filter(uid => {
      const u = byUser[uid];
      return u.total >= 10 && (u.wins / u.total) >= 0.65;
    });

    if (!sharpUserIds.length) { _sharpMoneyFeedCache.ts = Date.now(); _sharpMoneyFeedCache.data = []; return res.json([]); }

    const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
    let recentPositions = [];
    try {
      if (pool) {
        recentPositions = await dbQuery(
          'SELECT user_id, side, market_title, platform, created_at FROM cached_positions WHERE user_id = ANY($1) AND created_at >= $2 ORDER BY created_at DESC LIMIT 20',
          [sharpUserIds, cutoff]
        );
      } else {
        const { data: d } = await supabase
          .from('cached_positions')
          .select('user_id, side, market_title, platform, created_at')
          .in('user_id', sharpUserIds)
          .gte('created_at', cutoff)
          .order('created_at', { ascending: false })
          .limit(20);
        recentPositions = d || [];
      }
    } catch(e) { /* cached_positions may not exist */ }

    if (!recentPositions.length) { _sharpMoneyFeedCache.ts = Date.now(); _sharpMoneyFeedCache.data = []; return res.json([]); }

    const uids = [...new Set(recentPositions.map(p => p.user_id))];
    let nameRows;
    if (pool) {
      nameRows = await dbQuery('SELECT id, display_name FROM users WHERE id = ANY($1)', [uids]);
    } else {
      const { data } = await supabase.from('users').select('id, display_name').in('id', uids);
      nameRows = data;
    }
    const nameMap = {};
    for (const u of nameRows || []) nameMap[u.id] = u.display_name;

    const result = recentPositions.map(p => ({
      trader_name: nameMap[p.user_id] || 'Anonymous',
      trader_id: p.user_id,
      side: (p.side || 'YES').toUpperCase(),
      question: p.market_title || 'Unknown market',
      platform: p.platform || 'unknown',
      timestamp: p.created_at
    }));

    _sharpMoneyFeedCache.ts = Date.now();
    _sharpMoneyFeedCache.data = result;
    res.json(result.slice(0, limit));
  } catch (err) {
    console.error('[api/sharp-money-feed]', err);
    res.json([]);
  }
});

// Toggle follow a predictor
app.post('/api/predictors/:userId/follow', requireAuth, async (req, res) => {
  try {
    const followerId = req.user.id;
    const followingId = req.params.userId;
    if (followerId === followingId) return res.status(400).json({ error: 'Cannot follow yourself' });

    // following_id column is UUID with FK to users — validate before querying
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(followingId)) {
      // Non-UUID IDs (HL/Poly traders) — store in localStorage only, not DB
      return res.json({ following: true, client_only: true });
    }

    let existing;
    if (pool) {
      const rows = await dbQuery('SELECT id FROM predictor_follows WHERE follower_id = $1 AND following_id = $2 LIMIT 1', [followerId, followingId]);
      existing = rows[0] || null;
    } else {
      const { data } = await supabase.from('predictor_follows').select('id').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
      existing = data;
    }
    if (existing) {
      if (pool) { await dbQuery('DELETE FROM predictor_follows WHERE id = $1', [existing.id]); }
      else { await supabase.from('predictor_follows').delete().eq('id', existing.id); }
      return res.json({ following: false });
    } else {
      if (pool) { await dbQuery('INSERT INTO predictor_follows (follower_id, following_id) VALUES ($1, $2)', [followerId, followingId]); }
      else { await supabase.from('predictor_follows').insert({ follower_id: followerId, following_id: followingId }); }
      return res.json({ following: true });
    }
  } catch (e) {
    console.error('[follow]', e.message);
    res.status(500).json({ error: 'Follow failed' });
  }
});

