// FEATURE 2 — PUT /api/user/display-name
// Members set or update their display name from community.html
// ════════════════════════════════════════════════════════════
app.put('/api/user/display-name', requireAuth, async (req, res) => {
  try {
    const { display_name } = req.body;
    if (!display_name || !display_name.trim()) return res.status(400).json({ error: 'display_name required' });
    const name = display_name.trim().slice(0, 40);
    if (pool) {
      await dbQuery('UPDATE users SET display_name = $1 WHERE id = $2', [name, req.user.id]);
    } else {
      const { error } = await supabase.from('users').update({ display_name: name }).eq('id', req.user.id);
      if (error) return res.status(500).json({ error: error.message });
    }
    res.json({ ok: true, display_name: name });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ════════════════════════════════════════════════════════════
// PUT /api/user/change-password
// Works for both members and creators (all in users table).
// Requires current password + new password (min 8 chars).
// ════════════════════════════════════════════════════════════
app.put('/api/user/change-password', requireAuth, async (req, res) => {
  try {
    const { current_password, new_password } = req.body;
    if (!current_password || !new_password) {
      return res.status(400).json({ error: 'current_password and new_password are required' });
    }
    if (new_password.length < 8) {
      return res.status(400).json({ error: 'New password must be at least 8 characters' });
    }
    if (current_password === new_password) {
      return res.status(400).json({ error: 'New password must be different from current password' });
    }

    // Fetch current hash
    let user, fetchErr;
    if (pool) {
      const _rows = await dbQuery('SELECT password_hash FROM users WHERE id = $1 LIMIT 1', [req.user.id]);
      user = _rows[0] || null;
    } else {
      const { data: user, error: fetchErr } = await supabase .from('users') .select('password_hash') .eq('id', req.user.id) .single();
    }
    if (fetchErr || !user) return res.status(404).json({ error: 'User not found' });

    // Verify current password
    const valid = await bcrypt.compare(current_password, user.password_hash);
    if (!valid) return res.status(400).json({ error: 'Current password is incorrect' });

    // Hash and save new password
    const new_hash = await bcrypt.hash(new_password, 12);
    let updateErr;
    if (pool) {
      const _upd = { password_hash: new_hash };
      const _cols = Object.keys(_upd); const _vals = Object.values(_upd);
      const _set = _cols.map((c, i) => `${c} = $${i + 1}`).join(', ');
      const _where = [req.user.id];
      await dbQuery(`UPDATE users SET ${_set} WHERE id = $${_vals.length + 1}`, [..._vals, ..._where]);
    } else {
      const { error: updateErr } = await supabase .from('users') .update({ password_hash: new_hash }) .eq('id', req.user.id);
    }
    if (updateErr) return res.status(500).json({ error: updateErr.message });

    res.json({ ok: true });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

