app.post('/api/subscribe', async (req, res) => {
  const { email } = req.body || {};
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    return res.status(400).json({ error: 'Valid email required' });
  }
  try {
    if (pool) {
      await dbQuery(
        'INSERT INTO subscribers (email) VALUES ($1) ON CONFLICT (email) DO NOTHING',
        [email.toLowerCase().trim()]
      );
    } else {
      await supabase.from('subscribers').upsert({ email: email.toLowerCase().trim() }, { onConflict: 'email' });
    }
  } catch (err) {
    // Table may not exist yet — log but don't fail visibly
    console.warn('[subscribe] DB write failed (table may not exist):', err.message);
  }
  res.json({ ok: true, message: 'Subscribed! You\'ll get the daily whale briefing.' });
});

// ════════════════════════════════════════════════════════════
// WHALE PORTFOLIO PROFILES — full breakdown for a single whale
// ════════════════════════════════════════════════════════════
let _whaleProfileCache = new Map(); // address → { ts, data }

app.get('/api/whale-profile/:address', async (req, res) => {
  const address = (req.params.address || '').trim();
  if (!address) return res.status(400).json({ error: 'Address required' });

  try {
    // 10 min cache per address
    const cacheKey = address.toLowerCase();
    const cached = _whaleProfileCache.get(cacheKey);
    if (cached && (Date.now() - cached.ts < 10 * 60 * 1000)) {
      return res.json(cached.data);
    }

    // Get positions from whale watch cache
    const whaleData = (_whaleWatchCache && _whaleWatchCache.data) || null;
    const allPositions = (whaleData && whaleData.whales) || [];

    // Filter positions for this whale (match by proxyWallet or trader name)
    let positions = allPositions.filter(p =>
      (p.proxyWallet || '').toLowerCase() === cacheKey ||
      (p.trader || '').toLowerCase() === cacheKey
    );

    // If no match by wallet, try partial name match
    if (positions.length === 0) {
      positions = allPositions.filter(p =>
        (p.trader || '').toLowerCase().includes(cacheKey) ||
        cacheKey.includes((p.trader || '').toLowerCase())
      );
    }

    if (positions.length === 0) {
      return res.json({
        address,
        total_positions: 0,
        total_capital: 0,
        category_breakdown: [],
        top_positions: [],
        win_rate: 0,
        pnl: 0,
        risk_profile: 'Unknown',
        updated_at: new Date().toISOString()
      });
    }

    // Basic info from first position
    const traderName = positions[0].trader || 'Unknown';
    const traderRank = positions[0].trader_rank || 0;
    const traderPnl = positions[0].trader_pnl || 0;

    // Category breakdown
    const catKeywords = {
      sports: /nba|nfl|nhl|mlb|ufc|mma|soccer|football|baseball|basketball|hockey|tennis|golf|boxing|f1|championship|playoffs|super bowl|world cup|premier league|match|game/i,
      politics: /trump|biden|president|election|congress|senate|democrat|republican|governor|vote|political/i,
      crypto: /bitcoin|btc|ethereum|eth|solana|sol|crypto|defi|nft|token|dogecoin|xrp|binance/i,
      entertainment: /movie|oscar|grammy|emmy|album|netflix|spotify|tiktok|youtube|celebrity/i,
      tech: /ai |openai|chatgpt|apple|google|microsoft|meta |tesla|nvidia|amazon|startup|tech/i
    };

    function categorizePosition(q) {
      const text = (q || '').toLowerCase();
      for (const [cat, regex] of Object.entries(catKeywords)) {
        if (regex.test(text)) return cat;
      }
      return 'other';
    }

    const catMap = {};
    let totalCapital = 0;
    for (const p of positions) {
      const cat = categorizePosition(p.market);
      if (!catMap[cat]) catMap[cat] = 0;
      catMap[cat] += (p.size || 0);
      totalCapital += (p.size || 0);
    }

    const category_breakdown = Object.entries(catMap)
      .map(([category, capital]) => ({
        category,
        capital: Math.round(capital),
        pct: totalCapital > 0 ? Math.round(capital / totalCapital * 100) : 0
      }))
      .sort((a, b) => b.capital - a.capital);

    // Top positions by size
    const top_positions = [...positions]
      .sort((a, b) => (b.size || 0) - (a.size || 0))
      .slice(0, 5)
      .map(p => ({
        market: p.market,
        side: p.side,
        size: p.size,
        size_display: p.size >= 1000000 ? '$' + (p.size / 1000000).toFixed(1) + 'M' : p.size >= 1000 ? '$' + Math.round(p.size / 1000) + 'K' : '$' + Math.round(p.size),
        current_price: p.current_price,
        url: p.market_url
      }));

    // Risk profile based on concentration + position count
    const topPositionPct = positions.length > 0 && totalCapital > 0
      ? ((positions.sort((a, b) => (b.size || 0) - (a.size || 0))[0].size || 0) / totalCapital * 100)
      : 0;
    const uniqueCats = Object.keys(catMap).length;
    let risk_profile = 'Balanced';
    if (topPositionPct > 50 || uniqueCats <= 1) risk_profile = 'Aggressive';
    else if (positions.length > 10 && uniqueCats >= 3 && topPositionPct < 30) risk_profile = 'Conservative';

    const data = {
      address: positions[0].proxyWallet || address,
      name: traderName,
      rank: traderRank,
      pnl: traderPnl,
      total_positions: positions.length,
      total_capital: Math.round(totalCapital),
      total_capital_display: totalCapital >= 1000000 ? '$' + (totalCapital / 1000000).toFixed(1) + 'M' : totalCapital >= 1000 ? '$' + Math.round(totalCapital / 1000) + 'K' : '$' + Math.round(totalCapital),
      category_breakdown,
      top_positions,
      win_rate: 0, // No resolved data yet
      risk_profile,
      updated_at: new Date().toISOString()
    };

    _whaleProfileCache.set(cacheKey, { ts: Date.now(), data });
    // Cap cache at 200 entries
    if (_whaleProfileCache.size > 200) {
      const firstKey = _whaleProfileCache.keys().next().value;
      _whaleProfileCache.delete(firstKey);
    }
    res.json(data);
  } catch (err) {
    console.error('[whale-profile]', err.message);
    const stale = _whaleProfileCache.get(address.toLowerCase());
    if (stale) return res.json(stale.data);
    res.status(500).json({ error: 'Failed to build whale profile', detail: err.message });
  }
});

// ════════════════════════════════════════════════════════════
// POLYMARKET CLOB TRADING — API key derivation + HMAC order signing
// ════════════════════════════════════════════════════════════

// POST /api/polymarket/derive-api-key — derive CLOB API key from wallet signature
app.post('/api/polymarket/derive-api-key', requireAuth, async (req, res) => {
  const { address, signature, timestamp, nonce } = req.body;
  if (!address || !signature || !timestamp) {
    return res.status(400).json({ error: 'address, signature, and timestamp required' });
  }
  try {
    const upstream = await fetch('https://clob.polymarket.com/auth/derive-api-key', {
      method: 'GET',
      headers: {
        'POLY_ADDRESS': address,
        'POLY_SIGNATURE': signature,
        'POLY_TIMESTAMP': timestamp,
        'POLY_NONCE': nonce || '0',
        'Accept': 'application/json',
        'User-Agent': 'Hyperflex/1.0'
      }
    });
    const data = await upstream.json().catch(() => ({}));
    if (!upstream.ok) {
      console.error('[polymarket derive-api-key]', upstream.status, data);
      return res.status(upstream.status >= 400 && upstream.status < 500 ? upstream.status : 502).json({
        error: data.error || data.message || 'Failed to derive API key',
        detail: data
      });
    }
    let proxyAddress = data.proxyAddress || data.proxy_address || data.polyAddress || null;
    const apiKey = data.apiKey || data.api_key || null;
    const secret = data.secret || data.apiSecret || null;
    const passphrase = data.passphrase || null;

    // If derive-api-key didn't return proxy, fetch it from GET /auth/api-keys
    if (!proxyAddress && apiKey && secret && passphrase) {
      try {
        const keysRes = await fetch('https://clob.polymarket.com/auth/api-keys', {
          headers: {
            'POLY_ADDRESS': address,
            'POLY_API_KEY': apiKey,
            'POLY_API_SECRET': secret,
            'POLY_PASSPHRASE': passphrase,
            'Accept': 'application/json',
            'User-Agent': 'Hyperflex/1.0'
          }
        });
        if (keysRes.ok) {
          const keysData = await keysRes.json();
          // Response is array of api keys — each has a proxyAddress or polyAddress
          const keys = Array.isArray(keysData) ? keysData : [keysData];
          for (const k of keys) {
            const pa = k.proxyAddress || k.proxy_address || k.polyAddress || null;
            if (pa) { proxyAddress = pa; break; }
          }
        }
      } catch(e) { console.warn('[derive-api-key] api-keys lookup failed:', e.message); }
    }

    // Fallback: try L1-auth GET /auth/api-keys with original signature headers
    if (!proxyAddress) {
      try {
        const keysRes2 = await fetch('https://clob.polymarket.com/auth/api-keys', {
          headers: {
            'POLY_ADDRESS': address,
            'POLY_SIGNATURE': signature,
            'POLY_TIMESTAMP': timestamp,
            'POLY_NONCE': nonce || '0',
            'Accept': 'application/json'
          }
        });
        if (keysRes2.ok) {
          const keysData2 = await keysRes2.json();
          console.log('[derive-api-key] L1 api-keys response:', JSON.stringify(keysData2).slice(0, 300));
          const keys2 = Array.isArray(keysData2) ? keysData2 : [keysData2];
          for (const k of keys2) {
            const pa = k.proxyAddress || k.proxy_address || k.polyAddress || null;
            if (pa) { proxyAddress = pa; break; }
          }
        }
      } catch(e) { console.warn('[derive-api-key] L1 api-keys lookup failed:', e.message); }
    }

    // Fallback: compute proxy address using CREATE2 (both Safe and ProxyWallet factories)
    let _derivedAddresses = [];
    if (!proxyAddress) {
      try {
        const { createHash } = require('crypto');
        // Keccak-256 using ethers or crypto (Node.js doesn't have native keccak)
        // Use a simple approach: try both derived addresses and check which has positions
        const ethers = require('ethers');
        const addrLower = address.toLowerCase();

        // deriveSafe: encodeAbiParameters([{type:'address'}], [address])
        const safeFactory = '0xaacFeEa03eb1561C4e67d661e40682Bd20E3541b';
        const safeInitCodeHash = '0x2bce2127ff07fb632d16c8347c4ebf501f4841168bed00d9e6ef715ddb6fcecf';
        const abiEncoded = ethers.AbiCoder.defaultAbiCoder().encode(['address'], [addrLower]);
        const safeSalt = ethers.keccak256(abiEncoded);
        const safeAddr = ethers.getCreate2Address(safeFactory, safeSalt, safeInitCodeHash);

        // deriveProxyWallet: encodePacked([address])
        const proxyFactory = '0xaB45c5A4B0c941a2F231C04C3f49182e1A254052';
        const proxyInitCodeHash = '0xd21df8dc65880a8606f09fe0ce3df9b8869287ab0b058be05aa9e8af6330a00b';
        const proxySalt = ethers.keccak256(ethers.solidityPacked(['address'], [addrLower]));
        const proxyAddr = ethers.getCreate2Address(proxyFactory, proxySalt, proxyInitCodeHash);

        console.log(`[derive-api-key] CREATE2 derivation: safe=${safeAddr.slice(0,10)}... proxy=${proxyAddr.slice(0,10)}...`);
        _derivedAddresses = [safeAddr.toLowerCase(), proxyAddr.toLowerCase()];

        // Try server-side position check (may fail due to geo-blocking)
        for (const candidate of _derivedAddresses) {
          try {
            const checkRes = await fetch(`https://data-api.polymarket.com/positions?user=${candidate}&limit=1&sortBy=CURRENT`, {
              headers: { Accept: 'application/json' }
            });
            const checkData = await checkRes.json();
            if (Array.isArray(checkData) && checkData.length > 0) {
              proxyAddress = candidate;
              console.log(`[derive-api-key] Found positions at ${candidate.slice(0,10)}...`);
              break;
            }
          } catch(e) {}
        }
      } catch(e) { console.warn('[derive-api-key] CREATE2 derivation failed:', e.message); }
    }

    console.log(`[polymarket derive-api-key] user=${req.userId} address=${address.slice(0,8)}... proxy=${(proxyAddress||'none').slice(0,8)}... derived=${_derivedAddresses.length} keys: ${JSON.stringify(Object.keys(data))}`);

    // Save proxy address to user profile if we got one
    if (proxyAddress && req.userId && pool) {
      try {
        await dbQuery('UPDATE users SET polymarket_address = $1 WHERE id = $2 AND (polymarket_address IS NULL OR polymarket_address = $3)', [proxyAddress.toLowerCase(), req.userId, '']);
        await dbQuery('UPDATE creator_settings SET polymarket_address = $1 WHERE id = $2 AND (polymarket_address IS NULL OR polymarket_address = $3)', [proxyAddress.toLowerCase(), req.userId, '']);
      } catch(e) { /* silent */ }
    }

    res.json({
      apiKey: apiKey,
      secret: secret,
      passphrase: passphrase,
      proxyAddress: proxyAddress,
      derivedAddresses: _derivedAddresses
    });
  } catch (err) {
    console.error('[polymarket derive-api-key]', err.message);
    res.status(502).json({ error: 'Failed to derive API key from Polymarket', detail: err.message });
  }
});

// POST /api/polymarket/lookup-proxy — use existing API key to find proxy address
app.post('/api/polymarket/lookup-proxy', requireAuth, async (req, res) => {
  const { address, apiKey, secret, passphrase } = req.body;
  if (!address || !apiKey) return res.status(400).json({ error: 'Missing address or apiKey' });
  try {
    const keysRes = await fetch('https://clob.polymarket.com/auth/api-keys', {
      headers: {
        'POLY_ADDRESS': address,
        'POLY_API_KEY': apiKey,
        'POLY_API_SECRET': secret || '',
        'POLY_PASSPHRASE': passphrase || '',
        'Accept': 'application/json',
        'User-Agent': 'Hyperflex/1.0'
      }
    });
    if (!keysRes.ok) {
      const errText = await keysRes.text().catch(() => '');
      console.log(`[lookup-proxy] CLOB /auth/api-keys ${keysRes.status}: ${errText.slice(0, 200)}`);
      return res.json({ proxyAddress: null, error: 'CLOB returned ' + keysRes.status });
    }
    const keysData = await keysRes.json();
    console.log(`[lookup-proxy] CLOB response type=${typeof keysData} keys=${JSON.stringify(Array.isArray(keysData) ? keysData.map(k => Object.keys(k)) : Object.keys(keysData)).slice(0, 300)}`);

    let proxyAddress = null;
    const keys = Array.isArray(keysData) ? keysData : [keysData];
    for (const k of keys) {
      const pa = k.proxyAddress || k.proxy_address || k.polyAddress || k.address || null;
      if (pa && pa.toLowerCase() !== address.toLowerCase()) {
        proxyAddress = pa;
        break;
      }
    }

    // Save to DB
    if (proxyAddress && req.userId && pool) {
      try {
        await dbQuery('UPDATE users SET polymarket_address = $1 WHERE id = $2', [proxyAddress.toLowerCase(), req.userId]);
      } catch(e) { /* silent */ }
    }

    res.json({ proxyAddress });
  } catch (e) {
    console.error('[lookup-proxy]', e.message);
    res.json({ proxyAddress: null, error: e.message });
  }
});

// POST /api/polymarket/clob-order — submit order with HMAC-signed headers (no wallet signature needed)
app.post('/api/polymarket/clob-order', requireAuth, async (req, res) => {
  const { token_id, side, size, price, api_key, api_secret, api_passphrase } = req.body;
  if (!token_id || !side || !size || !price) {
    return res.status(400).json({ error: 'token_id, side, size, and price required' });
  }
  if (!api_key || !api_secret || !api_passphrase) {
    return res.status(400).json({ error: 'API credentials required. Enable trading first.' });
  }

  try {
    const ts = Math.floor(Date.now() / 1000).toString();
    const method = 'POST';
    const requestPath = '/order';
    const orderBody = JSON.stringify({
      tokenID: token_id,
      side: side.toUpperCase(),
      size: parseFloat(size).toString(),
      price: parseFloat(price).toString(),
      type: 'GTC'
    });

    // Create HMAC-SHA256 signature: timestamp + method + path + body
    const message = ts + method + requestPath + orderBody;
    const hmacSignature = crypto.createHmac('sha256', api_secret).update(message).digest('base64');

    // Builder attribution headers — gasless + volume tracking
    const builderHeaders = {};
    const builderKey = process.env.POLY_BUILDER_API_KEY;
    const builderSecret = process.env.POLY_BUILDER_SECRET;
    const builderPassphrase = process.env.POLY_BUILDER_PASSPHRASE;
    if (builderKey && builderSecret && builderPassphrase) {
      const builderTs = ts;
      const builderMessage = builderTs + method + requestPath + orderBody;
      const secretBuf = Buffer.from(builderSecret, 'base64');
      const builderSig = crypto.createHmac('sha256', secretBuf).update(builderMessage).digest('base64');
      builderHeaders['POLY_BUILDER_API_KEY'] = builderKey;
      builderHeaders['POLY_BUILDER_TIMESTAMP'] = builderTs;
      builderHeaders['POLY_BUILDER_PASSPHRASE'] = builderPassphrase;
      builderHeaders['POLY_BUILDER_SIGNATURE'] = builderSig;
      console.log('[builder] Attribution headers attached for order');
    }

    const upstream = await fetch('https://clob.polymarket.com/order', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'User-Agent': 'Hyperflex/1.0',
        'POLY_API_KEY': api_key,
        'POLY_PASSPHRASE': api_passphrase,
        'POLY_TIMESTAMP': ts,
        'POLY_SIGNATURE': hmacSignature,
        ...builderHeaders
      },
      body: orderBody
    });

    const data = await upstream.json().catch(() => ({}));
    if (!upstream.ok) {
      console.error('[polymarket clob-order]', upstream.status, data);
      return res.status(upstream.status >= 400 && upstream.status < 500 ? upstream.status : 502).json({
        error: data.error || data.message || 'Order rejected by Polymarket CLOB',
        detail: data
      });
    }

    console.log(`[polymarket clob-order] user=${req.userId} side=${side} size=${size} price=${price} token=${token_id.slice(0,12)}... status=ok`);
    res.json({
      success: true,
      order_id: data.orderID || data.order_id || data.id || null,
      ...data
    });
  } catch (err) {
    console.error('[polymarket clob-order]', err.message);
    res.status(502).json({ error: 'Failed to submit CLOB order', detail: err.message });
  }
});

// POST /api/polymarket/builder-sign — remote signing endpoint
// Client sends { method, path, body } → server returns builder HMAC headers
app.post('/api/polymarket/builder-sign', requireAuth, async (req, res) => {
  const builderKey = process.env.POLY_BUILDER_API_KEY;
  const builderSecret = process.env.POLY_BUILDER_SECRET;
  const builderPassphrase = process.env.POLY_BUILDER_PASSPHRASE;
  if (!builderKey || !builderSecret || !builderPassphrase) {
    return res.status(503).json({ error: 'Builder credentials not configured' });
  }
  const { method, path, body } = req.body;
  if (!method || !path) {
    return res.status(400).json({ error: 'method and path required' });
  }
  try {
    const ts = Math.floor(Date.now() / 1000).toString();
    const message = ts + (method || 'GET').toUpperCase() + path + (body || '');
    const secretBuf = Buffer.from(builderSecret, 'base64');
    const signature = crypto.createHmac('sha256', secretBuf).update(message).digest('base64');
    res.json({
      POLY_BUILDER_API_KEY: builderKey,
      POLY_BUILDER_TIMESTAMP: ts,
      POLY_BUILDER_PASSPHRASE: builderPassphrase,
      POLY_BUILDER_SIGNATURE: signature
    });
  } catch (err) {
    console.error('[builder-sign]', err.message);
    res.status(500).json({ error: 'Failed to generate builder signature' });
  }
});

// ════════════════════════════════════════════════════════════
// ALPHA SIGNALS — aggregated trading signals from all data sources
// ════════════════════════════════════════════════════════════
let _signalsCache = null;

app.get('/api/signals', async (req, res) => {
  try {
    // Check cache (5 min TTL)
    if (_signalsCache && (Date.now() - _signalsCache.ts < 5 * 60 * 1000)) {
      return res.json(_signalsCache.data);
    }

    // Pre-warm caches if empty
    if (!_whaleWatchCache || !_whaleWatchCache.data) {
      try {
        const whaleData = await fetchWhalePositions();
        _whaleWatchCache = { ts: Date.now(), data: whaleData };
        console.log('[signals] Warmed whale cache:', (whaleData.whales || []).length, 'positions');
      } catch(e) { console.warn('[signals] whale warm failed:', e.message); }
    }
    if (!_whaleIndexCache || !_whaleIndexCache.data) {
      // Build whale index inline from whale watch data
      if (_whaleWatchCache && _whaleWatchCache.data) {
        try {
          const whales = _whaleWatchCache.data.whales || [];
          // Step 1: Net out hedged positions per trader per market
          const netMap = {}; // key: "wallet:market" → { yes_cap, no_cap, ... }
          for (const w of whales) {
            const mkt = w.market || w.question;
            if (!mkt) continue;
            const wallet = (w.proxyWallet || w.trader || 'unknown').toLowerCase();
            const nk = wallet + ':' + mkt.toLowerCase();
            if (!netMap[nk]) netMap[nk] = { yes_cap: 0, no_cap: 0, market: mkt, wallet, url: w.market_url || w.url || '' };
            const side = (w.side || 'YES').toUpperCase();
            const cap = parseFloat(w.size || 0);
            if (side === 'YES' || side === 'Y') netMap[nk].yes_cap += cap;
            else netMap[nk].no_cap += cap;
          }
          // Step 2: Convert to net positions, skip fully hedged
          const netPositions = Object.values(netMap).map(n => {
            const net = n.yes_cap - n.no_cap;
            const side = net >= 0 ? 'YES' : 'NO';
            const size = Math.abs(net);
            if (size < 10) return null; // fully hedged
            return { market: n.market, side, size, url: n.url, wallet: n.wallet };
          }).filter(Boolean);
          // Step 3: Group by market
          const marketMap = {};
          for (const p of netPositions) {
            if (!marketMap[p.market]) marketMap[p.market] = { market: p.market, sides: {}, total_capital: 0, url: p.url, whale_count: 0 };
            if (!marketMap[p.market].sides[p.side]) marketMap[p.market].sides[p.side] = { capital: 0, count: 0 };
            marketMap[p.market].sides[p.side].capital += p.size;
            marketMap[p.market].sides[p.side].count++;
            marketMap[p.market].total_capital += p.size;
            marketMap[p.market].whale_count++;
          }
          const picks = Object.values(marketMap).filter(m => m.whale_count >= 3).map(m => {
            const sides = Object.entries(m.sides).sort((a,b) => b[1].capital - a[1].capital);
            const topSide = sides[0];
            return { market: m.market, whale_count: m.whale_count, total_capital: m.total_capital, consensus_side: topSide[0], consensus_pct: Math.round((topSide[1].capital / m.total_capital) * 100), url: m.url, strength: m.whale_count >= 10 ? 'STRONG' : m.whale_count >= 5 ? 'MODERATE' : 'EMERGING' };
          }).sort((a,b) => b.whale_count - a.whale_count);
          _whaleIndexCache = { ts: Date.now(), data: { picks } };
          console.log('[signals] Warmed whale index:', picks.length, 'picks');
        } catch(e) { console.warn('[signals] whale index build failed:', e.message); }
      }
    }
    if (!_marketMoversCache || !_marketMoversCache.data) {
      try {
        const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
        let rows = [];
        if (pool) {
          rows = await dbQuery('SELECT market_id, question, yes_price, snapshot_at FROM market_snapshots WHERE snapshot_at >= $1 ORDER BY market_id, snapshot_at ASC', [twentyFourHoursAgo]).catch(() => []);
        } else {
          const { data } = await supabase.from('market_snapshots').select('market_id, question, yes_price, snapshot_at').gte('snapshot_at', twentyFourHoursAgo).order('snapshot_at', { ascending: true });
          rows = data || [];
        }
        const mm = {};
        for (const r of rows) { if (!r.market_id) continue; if (!mm[r.market_id]) mm[r.market_id] = { question: r.question, first: r, last: r }; mm[r.market_id].last = r; mm[r.market_id].question = r.question || mm[r.market_id].question; }
        const movers = Object.entries(mm).map(([market_id, d]) => {
          const fp = parseFloat(d.first.yes_price)||0; const lp = parseFloat(d.last.yes_price)||0;
          const cp = fp > 0 ? Math.round((lp-fp)/fp*10000)/100 : 0;
          // Filter: skip near-zero baseline (noise), skip tiny absolute moves, skip resolved (99%+ or 1%-)
          if (fp < 0.03) return null; // near-zero start = noise
          if (Math.abs(lp - fp) < 0.03) return null; // less than 3¢ move
          if (lp >= 0.99 || lp <= 0.01) return null; // resolved market
          return { market_id, question: d.question||'Unknown', current_price: Math.round(lp*100), start_price: Math.round(fp*100), change_pct: cp, abs_change: Math.abs(cp), odds_change_pts: Math.round((lp-fp)*100), url: 'https://polymarket.com' };
        }).filter(Boolean).sort((a,b) => b.abs_change - a.abs_change).slice(0, 10).map(({abs_change,...rest}) => rest);
        _marketMoversCache = { ts: Date.now(), data: { movers, updated_at: new Date().toISOString() } };
        console.log('[signals] Warmed movers cache:', movers.length, 'movers');
      } catch(e) { console.warn('[signals] movers warm failed:', e.message); }
    }
    // Warm volume baseline cache (7-day avg volume per market, 30-min TTL)
    if (!_volumeBaselineCache || (Date.now() - _volumeBaselineCache.ts > 30 * 60 * 1000)) {
      try {
        const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
        let vRows = [];
        if (pool) {
          vRows = await dbQuery('SELECT market_id, AVG(volume) as avg_volume FROM market_snapshots WHERE snapshot_at >= $1 AND volume > 0 GROUP BY market_id', [sevenDaysAgo]).catch(() => []);
        } else {
          // Supabase doesn't support AVG in select — fetch raw and compute in JS
          const { data } = await supabase.from('market_snapshots').select('market_id, volume').gte('snapshot_at', sevenDaysAgo).gt('volume', 0);
          const sums = {};
          for (const r of (data || [])) { if (!r.market_id) continue; if (!sums[r.market_id]) sums[r.market_id] = { total: 0, count: 0 }; sums[r.market_id].total += parseFloat(r.volume) || 0; sums[r.market_id].count++; }
          vRows = Object.entries(sums).map(([market_id, s]) => ({ market_id, avg_volume: s.total / s.count }));
        }
        const baseline = {};
        for (const r of vRows) { if (r.market_id && r.avg_volume) baseline[r.market_id] = parseFloat(r.avg_volume); }
        _volumeBaselineCache = { ts: Date.now(), data: baseline };
        console.log('[signals] Warmed volume baseline:', Object.keys(baseline).length, 'markets');
      } catch(e) { console.warn('[signals] volume baseline warm failed:', e.message); }
    }

    let signals = [];
    const now = new Date().toISOString();

    // Source 1: Whale clustering — markets with 5+ whales from whale-index
    try {
      if (_whaleIndexCache && _whaleIndexCache.data) {
        const wiData = _whaleIndexCache.data;
        const markets = wiData.picks || wiData.markets || wiData.positions || [];
        for (const m of markets) {
          const whaleCount = m.whale_count || m.whales || 0;
          if (whaleCount >= 3) {
            const consensus = m.consensus_pct || m.consensus || 0;
            const consensusSide = m.consensus_side || (consensus > 50 ? 'YES' : 'NO');
            // Cross-reference screener cache for end_date and yes_pct
            let endDate = null;
            let yesPct = consensus;
            if (_screenerCache && _screenerCache.data) {
              const mktQ = (m.market || m.question || '').toLowerCase();
              const match = _screenerCache.data.find(sm => (sm.question || '').toLowerCase() === mktQ);
              if (match) {
                endDate = match.end_date || null;
                if (match.yes_price != null) yesPct = Math.round(match.yes_price * 100);
              }
            }
            // Skip resolved markets (price at 0% or 100%)
            if (yesPct >= 99 || yesPct <= 1) continue;
            // Skip expired/closed markets
            if (endDate && new Date(endDate) < new Date()) continue;
            // Skip markets not found in screener (likely closed/delisted)
            if (_screenerCache && _screenerCache.data && _screenerCache.data.length > 10) {
              const mktQ2 = (m.market || m.question || '').toLowerCase();
              const inScreener = _screenerCache.data.some(sm => (sm.question || '').toLowerCase() === mktQ2);
              if (!inScreener) continue; // not in active markets = closed
            }
            signals.push({
              type: 'whale_cluster',
              badge: 'Whale Cluster',
              market: m.market || m.question || 'Unknown',
              action: `BUY ${consensusSide} at ${consensus}%`,
              side: consensusSide,
              price: consensus / 100,
              confidence: whaleCount >= 10 ? 'HIGH' : whaleCount >= 7 ? 'MEDIUM' : 'LOW',
              whale_count: whaleCount,
              capital: m.total_capital || m.capital || 0,
              yes_pct: yesPct,
              end_date: endDate,
              detected_at: now,
              url: m.url || 'https://polymarket.com'
            });
          }
        }
      }
    } catch (e) { console.warn('[signals] whale-cluster source error:', e.message); }

    // Source 2: Price velocity — markets that moved 10%+ in last 24h from market-movers
    try {
      if (_marketMoversCache && _marketMoversCache.data) {
        const movers = _marketMoversCache.data.movers || [];
        for (const m of movers) {
          const absChange = Math.abs(m.change_pct || 0);
          if (absChange >= 5) {
            // BUY direction must match price movement
            const priceUp = (m.current_price || 50) > (m.start_price || 0);
            const direction = priceUp ? 'YES' : 'NO';
            // Skip resolved markets (price at 0 or 100)
            if ((m.current_price || 50) >= 99 || (m.current_price || 50) <= 1) continue;
            // Skip near-zero baseline (noise)
            if ((m.start_price || 0) < 3) continue;
            // Skip tiny absolute moves (less than 3¢)
            if (Math.abs((m.current_price || 0) - (m.start_price || 0)) < 3) continue;
            signals.push({
              type: 'momentum',
              badge: 'Momentum',
              market: m.question || 'Unknown',
              action: `BUY ${direction} — odds: ${m.start_price || '?'}\u00A2 \u2192 ${m.current_price || '?'}\u00A2`,
              side: direction,
              price: (m.current_price || 50) / 100,
              confidence: absChange >= 25 ? 'HIGH' : absChange >= 15 ? 'MEDIUM' : 'LOW',
              whale_count: 0,
              change_pct: m.change_pct,
              start_price: m.start_price || null,
              odds_price: m.current_price || null,
              detected_at: now,
              url: m.url || 'https://polymarket.com'
            });
          }
        }
      }
    } catch (e) { console.warn('[signals] momentum source error:', e.message); }

    // Source 3: Whale momentum — new positions from whale trade stream
    try {
      const recentTrades = (_whaleTradeStream || []).filter(t => {
        const age = Date.now() - new Date(t.ts).getTime();
        return age < 24 * 60 * 60 * 1000 && t.type === 'opened';
      });
      for (const t of recentTrades.slice(0, 10)) {
        const p = t.position || {};
        // Skip resolved markets
        if ((p.current_price || 0) >= 0.99 || (p.current_price || 0) <= 0.01) continue;
        signals.push({
          type: 'new_entry',
          badge: 'New Entry',
          market: p.title || p.market || 'Unknown',
          action: `${t.trader_name || t.trader?.name || 'Whale'} opened ${p.outcome || 'YES'} position`,
          side: p.outcome || 'YES',
          price: p.current_price || 0,
          confidence: (parseFloat(p.size) || 0) >= 50000 ? 'HIGH' : (parseFloat(p.size) || 0) >= 10000 ? 'MEDIUM' : 'LOW',
          whale_count: 1,
          capital: parseFloat(p.size) || 0,
          detected_at: t.ts || now,
          url: p.market_url || 'https://polymarket.com'
        });
      }
    } catch (e) { console.warn('[signals] whale-stream source error:', e.message); }

    // Source 4: Cross-platform arbitrage — compare Polymarket vs Kalshi prices from market search cache
    try {
      for (const [, cached] of _mktSearchCache) {
        if (!cached || !cached.data) continue;
        const polyMarkets = cached.data.polymarket || [];
        const kalshiMarkets = cached.data.kalshi || [];
        // Simple keyword match between platforms
        for (const pm of polyMarkets) {
          for (const km of kalshiMarkets) {
            const pQ = (pm.question || '').toLowerCase();
            const kQ = (km.question || km.title || '').toLowerCase();
            // Check for significant keyword overlap
            const pWords = pQ.split(/\s+/).filter(w => w.length > 4);
            const kWords = kQ.split(/\s+/).filter(w => w.length > 4);
            const overlap = pWords.filter(w => kWords.includes(w)).length;
            if (overlap >= 3) {
              const pPrice = (pm.yes_price || pm.yes_pct || 50) / 100;
              const kPrice = (km.yes_price || km.yes_pct || 50) / 100;
              const diff = Math.abs(pPrice - kPrice);
              if (diff > 0.03) {
                const cheaperPlatform = pPrice < kPrice ? 'Polymarket' : 'Kalshi';
                const cheaperPrice = Math.min(pPrice, kPrice);
                signals.push({
                  type: 'arbitrage',
                  badge: 'Arbitrage',
                  market: pm.question || km.question || 'Unknown',
                  action: `${(diff * 100).toFixed(1)}% gap — buy YES on ${cheaperPlatform} at ${(cheaperPrice * 100).toFixed(0)}%`,
                  side: 'YES',
                  price: cheaperPrice,
                  confidence: diff > 0.08 ? 'HIGH' : diff > 0.05 ? 'MEDIUM' : 'LOW',
                  whale_count: 0,
                  price_diff: diff,
                  detected_at: now,
                  url: pm.url || 'https://polymarket.com'
                });
              }
            }
          }
        }
        break; // Only check first cached search result
      }
    } catch (e) { console.warn('[signals] arbitrage source error:', e.message); }

    // Source 5: Volume Surge — unusual volume, price velocity, and whale convergence
    try {
      const CROSS_ASSET_MAP = {
        'iran|hormuz|persian gulf': 'Watch: crude oil futures (CL), defense ETFs (ITA)',
        'tariff|trade war|import duty': 'Watch: S&P 500 (ES), USD/CNY',
        'fed |federal reserve|rate cut|rate hike|interest rate': 'Watch: Treasury yields (TLT), gold (GC)',
        'ukraine|russia|nato|kyiv|putin': 'Watch: natural gas (NG), wheat futures (ZW)',
        'bitcoin|btc |ethereum|eth |crypto': 'Watch: MSTR, COIN, mining ETFs (WGMI)',
        'election|president|democrat|republican': 'Watch: Russell 2000 (IWM), Treasury yields',
        'oil|opec|crude|petroleum|energy': 'Watch: crude oil futures (CL), energy ETFs (XLE)',
        'china|xi jinping|taiwan|south china sea': 'Watch: FXI, KWEB, USD/CNY',
      };

      function getCrossAssetHint(question) {
        const q = (question || '').toLowerCase();
        for (const [pattern, hint] of Object.entries(CROSS_ASSET_MAP)) {
          if (new RegExp(pattern, 'i').test(q)) return hint;
        }
        return '';
      }

      const screenerMkts = (_screenerCache && _screenerCache.data) || [];
      const baseline = (_volumeBaselineCache && _volumeBaselineCache.data) || {};
      const recentWhaleEvents = (_whaleTradeStream || []).filter(t => {
        const age = Date.now() - new Date(t.ts).getTime();
        return age < 60 * 60 * 1000 && (t.action === 'opened' || t.action === 'increased');
      });

      for (const m of screenerMkts) {
        if (!m.market_id || !m.question) continue;
        const currentVol = m.volume || 0;
        const baselineVol = baseline[m.market_id] || 0;

        // ── Component 1: Volume Spike Score (0-100) ──
        let volumeRatio = 1;
        let volumeScore = 0;
        if (baselineVol > 10000 && currentVol > 0) {
          volumeRatio = currentVol / baselineVol;
          volumeScore = Math.min(100, Math.max(0, (volumeRatio - 1) * 50));
        }

        // ── Component 2: Price Velocity Score (0-100) ──
        let velocityScore = 0;
        let rapidMoveCount = 0;
        const tracker = _volumeTracker[m.market_id];
        if (tracker && tracker.samples.length >= 3) {
          // Count rapid price moves (>2c change between consecutive samples) in 2h window
          for (let i = 1; i < tracker.samples.length; i++) {
            const prev = tracker.samples[i-1];
            const curr = tracker.samples[i];
            if (prev.yes_price != null && curr.yes_price != null) {
              const delta = Math.abs(curr.yes_price - prev.yes_price);
              if (delta > 0.02) rapidMoveCount++;
            }
          }
          velocityScore = Math.min(100, rapidMoveCount * 25);
        }

        // ── Component 3: Whale Convergence Score (0-100) ──
        const mktQ = m.question.toLowerCase().trim();
        const whalesInMarket = new Set();
        for (const we of recentWhaleEvents) {
          const weQ = (we.question || we.market || '').toLowerCase().trim();
          if (weQ === mktQ || (weQ.length > 30 && mktQ.length > 30 && weQ.substring(0, 30) === mktQ.substring(0, 30))) {
            whalesInMarket.add(we.trader_name || we.trader);
          }
        }
        const whaleConvergence = whalesInMarket.size;
        const convergenceScore = Math.min(100, whaleConvergence * 33);

        // ── Combined Score ──
        const combined = volumeScore * 0.4 + velocityScore * 0.3 + convergenceScore * 0.3;
        if (combined < 30) continue; // Not unusual enough

        // Skip resolved markets
        const yesPct = m.yes_price != null ? Math.round(m.yes_price * 100) : 50;
        if (yesPct >= 99 || yesPct <= 1) continue;
        // Skip expired
        if (m.end_date && new Date(m.end_date) < new Date()) continue;

        // Determine confidence
        const confidence = combined >= 70 ? 'HIGH' : combined >= 45 ? 'MEDIUM' : 'LOW';

        // Build action text
        const parts = [];
        if (volumeRatio >= 1.5) parts.push(volumeRatio.toFixed(1) + 'x volume surge');
        if (rapidMoveCount >= 2) parts.push(rapidMoveCount + ' rapid price moves in 2h');
        if (whaleConvergence >= 2) parts.push(whaleConvergence + ' whale entries in 1h');
        if (parts.length === 0) parts.push('Unusual market activity detected');
        let actionText = parts.join(' + ');
        const crossAssetHint = getCrossAssetHint(m.question);
        if (crossAssetHint) actionText += ' \u2014 ' + crossAssetHint;

        // Determine dominant side from price movement
        let side = 'YES';
        if (tracker && tracker.samples.length >= 2) {
          const firstP = tracker.samples[0].yes_price || 0.5;
          const lastP = tracker.samples[tracker.samples.length - 1].yes_price || 0.5;
          side = lastP >= firstP ? 'YES' : 'NO';
        }

        signals.push({
          type: 'volume_surge',
          badge: 'Volume Surge',
          market: m.question,
          action: actionText,
          side,
          price: m.yes_price || 0.5,
          confidence,
          whale_count: whaleConvergence,
          capital: 0,
          volume_ratio: Math.round(volumeRatio * 10) / 10,
          volume_24h: currentVol,
          rapid_moves: rapidMoveCount,
          yes_pct: yesPct,
          end_date: m.end_date || null,
          detected_at: now,
          url: m.url || 'https://polymarket.com',
          slug: m.slug || ''
        });
      }
    } catch (e) { console.warn('[signals] volume-surge source error:', e.message); }

    // ── Global filter: remove obviously closed/expired markets ──
    const activeMarketQuestions = new Set();
    if (_screenerCache && Array.isArray(_screenerCache.data) && _screenerCache.data.length > 20) {
      _screenerCache.data.forEach(m => { if (m.question) activeMarketQuestions.add(m.question.toLowerCase().trim()); });
      signals = signals.filter(sig => {
        const q = (sig.market || '').toLowerCase().trim();
        if (!q) return true;
        // Keep signals with whale data regardless of screener match
        if (sig.whale_count >= 2 || sig.capital >= 10000) return true;
        // If in screener, keep
        if (activeMarketQuestions.has(q)) return true;
        // Fuzzy: check if first 30 chars match any active market
        const prefix = q.substring(0, 30);
        for (const aq of activeMarketQuestions) { if (aq.startsWith(prefix)) return true; }
        return false;
      });
    }
    // Also filter by end_date if available
    signals = signals.filter(sig => {
      if (!sig.end_date) return true;
      return new Date(sig.end_date) > new Date();
    });

    // ── Dedup signals by base question (strip date variants) ──
    function _baseQuestion(q) {
      return (q || '')
        .replace(/\s+by\s+(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\w*\s+\d{1,2}[,]?\s*(\d{4})?(\?)?$/i, '')
        .replace(/\s+by\s+\w+\s+\d{4}(\?)?$/i, '')
        .replace(/\s+before\s+(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\w*\s+\d{1,2}(\?)?$/i, '')
        .replace(/\s+in\s+(q[1-4]|q[1-4]\s+\d{4}|\d{4})(\?)?$/i, '')
        .replace(/\s+(by|before|in|through|until)\s+\d{4}(\?)?$/i, '')
        .replace(/\s+on\s+\d{4}-\d{2}-\d{2}(\?)?$/i, '')
        .replace(/\s+\d{4}-\d{2}-\d{2}(\?)?$/, '')
        .replace(/\?$/, '').trim().toLowerCase();
    }
    const _dedupSeen = new Map();
    for (const sig of signals) {
      const base = _baseQuestion(sig.market || '');
      if (!base) { _dedupSeen.set(sig.market + Math.random(), { ...sig, _altCount: 0 }); continue; }
      const existing = _dedupSeen.get(base);
      if (!existing) {
        _dedupSeen.set(base, { ...sig, _altCount: 0 });
      } else {
        const eScore = (existing.whale_count || 0) * 10 + (existing.capital || 0) / 1000;
        const nScore = (sig.whale_count || 0) * 10 + (sig.capital || 0) / 1000;
        if (nScore > eScore) {
          _dedupSeen.set(base, { ...sig, _altCount: existing._altCount + 1 });
        } else {
          existing._altCount++;
        }
      }
    }
    let deduped = Array.from(_dedupSeen.values());

    // ── Per-narrative cap: max 2 signals per theme ──
    function _signalNarrative(market) {
      const q = (market || '').toLowerCase();
      if (/trump|president|democrat|republican|congress|senate|maga|white house|tariff|vance/i.test(q)) return 'Trump & US Politics';
      if (/bitcoin|btc|ethereum|eth|crypto|solana|sol|defi|nft|coinbase|xrp|dogecoin/i.test(q)) return 'Crypto & DeFi';
      if (/israel|iran|gaza|hamas|hezbollah|ceasefire|hormuz|middle east|lebanon/i.test(q)) return 'Middle East & War';
      if (/\bai\b|openai|gpt|artificial intelligence|nvidia|apple|microsoft|google|meta /i.test(q)) return 'AI & Big Tech';
      if (/\bfed\b|federal reserve|interest rate|inflation|recession|gdp|cpi|unemployment|rate cut|crude oil/i.test(q)) return 'Macro & Economy';
      if (/ukraine|russia|zelensky|putin|nato|kyiv/i.test(q)) return 'Ukraine & Russia';
      if (/nba|basketball|finals|playoff|lakers|celtics|warriors|nuggets|cavaliers|thunder|knicks/i.test(q)) return 'NBA & Basketball';
      if (/nfl|super bowl|mlb|world series|nhl|stanley cup|ncaa/i.test(q)) return 'NFL & American Sports';
      if (/election|vote|ballot|candidate|prime minister|chancellor/i.test(q)) return 'Global Elections';
      return 'Other';
    }
    const _narrativeCounts = {};
    const diversified = [];
    for (const sig of deduped) {
      const narr = _signalNarrative(sig.market || '');
      sig._narrative = narr;
      _narrativeCounts[narr] = (_narrativeCounts[narr] || 0) + 1;
      if (narr === 'Other' || _narrativeCounts[narr] <= 2) {
        diversified.push(sig);
      }
    }

    // ── Fallback: if all sources produced 0 signals, synthesize from raw whale data ──
    if (diversified.length === 0 && _whaleWatchCache && _whaleWatchCache.data) {
      try {
        const whales = _whaleWatchCache.data.whales || [];
        // Net out hedged positions per trader per market
        const fbNetMap = {};
        for (const w of whales) {
          const mkt = w.market || w.question;
          if (!mkt) continue;
          const wallet = (w.proxyWallet || w.trader || 'unknown').toLowerCase();
          const nk = wallet + ':' + mkt.toLowerCase();
          if (!fbNetMap[nk]) fbNetMap[nk] = { yes_cap: 0, no_cap: 0, market: mkt, wallet, url: w.market_url || w.url || 'https://polymarket.com' };
          const side = (w.side || 'YES').toUpperCase();
          const cap = parseFloat(w.size || 0);
          if (side === 'YES' || side === 'Y') fbNetMap[nk].yes_cap += cap;
          else fbNetMap[nk].no_cap += cap;
        }
        const fbNet = Object.values(fbNetMap).map(n => {
          const net = n.yes_cap - n.no_cap;
          if (Math.abs(net) < 10) return null;
          return { market: n.market, side: net >= 0 ? 'YES' : 'NO', size: Math.abs(net), url: n.url, wallet: n.wallet };
        }).filter(Boolean);
        // Group by market
        const mktMap = {};
        for (const p of fbNet) {
          if (!mktMap[p.market]) mktMap[p.market] = { market: p.market, sides: {}, total_capital: 0, whale_count: 0, url: p.url };
          if (!mktMap[p.market].sides[p.side]) mktMap[p.market].sides[p.side] = { capital: 0, count: 0 };
          mktMap[p.market].sides[p.side].capital += p.size;
          mktMap[p.market].sides[p.side].count++;
          mktMap[p.market].total_capital += p.size;
          mktMap[p.market].whale_count++;
        }
        const fallbackMarkets = Object.values(mktMap)
          .filter(m => m.whale_count >= 2)
          .sort((a, b) => b.whale_count - a.whale_count || b.total_capital - a.total_capital)
          .slice(0, 10);
        for (const m of fallbackMarkets) {
          const sides = Object.entries(m.sides).sort((a, b) => b[1].capital - a[1].capital);
          const topSide = sides[0] || ['YES', { capital: 0, count: 0 }];
          const consensus = m.total_capital > 0 ? Math.round((topSide[1].capital / m.total_capital) * 100) : 50;
          diversified.push({
            type: 'whale_cluster',
            badge: 'Whale Cluster',
            market: m.market,
            action: `${m.whale_count} whales, ${consensus}% ${topSide[0]}`,
            side: topSide[0],
            price: consensus / 100,
            confidence: m.whale_count >= 5 ? 'HIGH' : m.whale_count >= 3 ? 'MEDIUM' : 'LOW',
            whale_count: m.whale_count,
            capital: m.total_capital,
            detected_at: now,
            url: m.url
          });
        }
        console.log('[signals] Fallback: synthesized', diversified.length, 'signals from whale data');
      } catch (e) { console.warn('[signals] fallback error:', e.message); }
    }

    // Sort: weighted score (confidence + source track record + whale count + recency)
    const confScore = { HIGH: 30, MEDIUM: 20, LOW: 10 };
    diversified.forEach(sig => {
      const conf = confScore[sig.confidence] || 15;
      const whales = (sig.whale_count || 0) * 2;
      const sourceW = getSourceWeight(sig._narrative || sig.type || 'unknown');
      const recency = Math.max(0, 10 - (Date.now() - new Date(sig.detected_at || 0).getTime()) / 3600000); // 0-10 pts, decays over 10h
      sig._score = Math.round((conf + whales + recency) * sourceW * 10) / 10;
    });
    diversified.sort((a, b) => (b._score || 0) - (a._score || 0));

    const finalSignals = diversified.slice(0, 20);

    // Enrich every signal with Alpha Score (0-10)
    const eliteData = getEliteWhales();
    const whaleIdx = (_whaleIndexCache && _whaleIndexCache.data) ? _whaleIndexCache.data.picks || [] : [];
    for (const sig of finalSignals) {
      const mkt = { question: sig.market, market: sig.market, yes_price: sig.price || 0.5 };
      // Add wallets to whale index entries for alpha score computation
      const idxEntry = whaleIdx.find(w => w.market === sig.market);
      if (idxEntry && !idxEntry.wallets) {
        // Collect wallets from raw positions for this market
        const allWhales = (_whaleWatchCache && _whaleWatchCache.data) ? _whaleWatchCache.data.whales || [] : [];
        idxEntry.wallets = [...new Set(allWhales.filter(w => w.market === sig.market).map(w => w.proxyWallet).filter(Boolean))];
      }
      sig.alpha_score = computeMarketAlphaScore(mkt, whaleIdx, eliteData.scores);
    }

    // Intelligence feedback loop: log every signal for outcome tracking
    for (const sig of finalSignals) { logSignalOutcome(sig); }

    const result = {
      signals: finalSignals,
      total: diversified.length,
      updated_at: now
    };

    _signalsCache = { ts: Date.now(), data: result };
    _healthTimestamps.lastSignalCompute = new Date().toISOString();
    res.json(result);
  } catch (err) {
    console.error('[signals]', err.message);
    if (_signalsCache) return res.json(_signalsCache.data);
    res.status(500).json({ error: 'Failed to compute signals', detail: err.message });
  }
});

