// ════════════════════════════════════════════════════════════
// SPREAD SCANNER — Live orderbook pair cost monitoring
// ════════════════════════════════════════════════════════════
let _spreadCache = { ts: 0, data: [] };

app.get('/api/spread-scanner', async (req, res) => {
  // Return cached data if fresh (< 15s old)
  if (_spreadCache.data.length && Date.now() - _spreadCache.ts < 15000) {
    return res.json({ markets: _spreadCache.data, updated_at: new Date(_spreadCache.ts).toISOString() });
  }
  try {
    // 1. Fetch all open "Up or Down" crypto window markets from gamma markets API
    // Note: these are under /markets not /events on gamma
    const allWindowMarkets = [];
    const now = Date.now();

    // Fetch multiple pages to get all crypto windows
    for (let offset = 0; offset < 400; offset += 100) {
      try {
        const gammaRes = await fetch(`https://gamma-api.polymarket.com/markets?closed=false&limit=100&offset=${offset}&order=startDate&ascending=false`, {
          headers: { Accept: 'application/json', 'User-Agent': 'Hyperflex/1.0' }
        });
        if (!gammaRes.ok) break;
        const gammaData = await gammaRes.json();
        const markets = Array.isArray(gammaData) ? gammaData : [];
        if (!markets.length) break;
        allWindowMarkets.push(...markets);
      } catch { break; }
    }

    const windowMarkets = [];
    for (const m of allWindowMarkets) {
      const q = (m.question || '').toLowerCase();
      // Only short-duration crypto "Up or Down" markets
      if (!q.includes('up or down')) continue;
      const isCrypto = /bitcoin|btc|ethereum|eth|solana|sol|xrp|dogecoin|doge|bnb|hype|hyperliquid/i.test(q);
      if (!isCrypto) continue;

      let tids = m.clobTokenIds || '[]';
      if (typeof tids === 'string') try { tids = JSON.parse(tids); } catch { tids = []; }
      if (tids.length < 2) continue;

      // Parse end date to filter near-term only (within 24h)
      const endDate = new Date(m.endDate || m.close_time || '');
      const hoursToEnd = (endDate.getTime() - now) / 3600000;
      if (hoursToEnd < -1 || hoursToEnd > 24) continue;

      // Extract asset name
      let asset = 'BTC';
      if (/ethereum|eth\b/i.test(q)) asset = 'ETH';
      else if (/solana|sol\b/i.test(q)) asset = 'SOL';
      else if (/xrp/i.test(q)) asset = 'XRP';
      else if (/dogecoin|doge/i.test(q)) asset = 'DOGE';
      else if (/bnb/i.test(q)) asset = 'BNB';
      else if (/hype|hyperliquid/i.test(q)) asset = 'HYPE';

      windowMarkets.push({
        question: m.question,
        asset,
        endDate: endDate.toISOString(),
        hoursToEnd: Math.max(0, hoursToEnd),
        yesTokenId: tids[0],
        noTokenId: tids[1],
        conditionId: m.conditionId,
        slug: m.market_slug || m.slug || '',
        volume: m.volumeNum || m.volume || 0
      });
    }

    // 2. Fetch orderbooks for the nearest markets (limit to 30 to avoid rate limiting)
    const nearest = windowMarkets
      .filter(m => m.hoursToEnd >= 0)
      .sort((a, b) => a.hoursToEnd - b.hoursToEnd)
      .slice(0, 30);

    const results = [];
    const fetchBook = async (tokenId) => {
      try {
        const r = await fetch(`https://clob.polymarket.com/book?token_id=${tokenId}`, {
          headers: { Accept: 'application/json' }
        });
        if (!r.ok) return { bids: [], asks: [] };
        return await r.json();
      } catch { return { bids: [], asks: [] }; }
    };

    // Fetch in batches of 6 (12 requests = 6 markets at a time)
    for (let i = 0; i < nearest.length; i += 6) {
      const batch = nearest.slice(i, i + 6);
      const bookPromises = batch.flatMap(m => [
        fetchBook(m.yesTokenId).then(b => ({ market: m, side: 'yes', book: b })),
        fetchBook(m.noTokenId).then(b => ({ market: m, side: 'no', book: b }))
      ]);
      const books = await Promise.allSettled(bookPromises);

      // Pair YES+NO books per market
      const marketBooks = {};
      for (const result of books) {
        if (result.status !== 'fulfilled') continue;
        const { market, side, book } = result.value;
        const key = market.conditionId;
        if (!marketBooks[key]) marketBooks[key] = { market, yes: null, no: null };
        marketBooks[key][side] = book;
      }

      for (const { market, yes, no } of Object.values(marketBooks)) {
        if (!yes || !no) continue;
        const yesAsks = (yes.asks || []).sort((a, b) => parseFloat(a.price) - parseFloat(b.price));
        const noAsks = (no.asks || []).sort((a, b) => parseFloat(a.price) - parseFloat(b.price));
        const yesBids = (yes.bids || []).sort((a, b) => parseFloat(b.price) - parseFloat(a.price));
        const noBids = (no.bids || []).sort((a, b) => parseFloat(b.price) - parseFloat(a.price));

        if (!yesAsks.length || !noAsks.length) continue;

        const yesAsk = parseFloat(yesAsks[0].price);
        const noAsk = parseFloat(noAsks[0].price);
        const yesAskSize = parseFloat(yesAsks[0].size);
        const noAskSize = parseFloat(noAsks[0].size);
        const yesBid = yesBids.length ? parseFloat(yesBids[0].price) : 0;
        const noBid = noBids.length ? parseFloat(noBids[0].price) : 0;

        const pairCost = yesAsk + noAsk;
        const spread = 1.0 - pairCost;
        const maxPairs = Math.min(yesAskSize, noAskSize);
        const profitPerPair = Math.max(0, spread);
        const totalProfit = maxPairs * profitPerPair;
        const isArb = spread > 0.001; // > 0.1% spread

        // Calculate depth — how much liquidity at each price level
        const yesDepth = yesAsks.slice(0, 5).reduce((s, a) => s + parseFloat(a.size), 0);
        const noDepth = noAsks.slice(0, 5).reduce((s, a) => s + parseFloat(a.size), 0);

        results.push({
          question: market.question,
          asset: market.asset,
          endDate: market.endDate,
          hoursToEnd: market.hoursToEnd,
          minutesToEnd: Math.round(market.hoursToEnd * 60),
          slug: market.slug,
          conditionId: market.conditionId,
          volume: market.volume,
          // Orderbook data
          yesAsk, noAsk, yesBid, noBid,
          yesAskSize: Math.round(yesAskSize),
          noAskSize: Math.round(noAskSize),
          yesDepth: Math.round(yesDepth),
          noDepth: Math.round(noDepth),
          // Spread analysis
          pairCost: Math.round(pairCost * 10000) / 10000,
          spread: Math.round(spread * 10000) / 10000,
          spreadPct: Math.round(spread * 10000) / 100,
          maxPairs: Math.round(maxPairs),
          profitPerPair: Math.round(profitPerPair * 10000) / 10000,
          totalProfit: Math.round(totalProfit * 100) / 100,
          isArb,
          // Status
          status: market.hoursToEnd < 0.083 ? 'IMMINENT' : market.hoursToEnd < 1 ? 'SOON' : 'UPCOMING'
        });
      }
    }

    // Sort: arbs first (by spread desc), then by time to end
    results.sort((a, b) => {
      if (a.isArb && !b.isArb) return -1;
      if (!a.isArb && b.isArb) return 1;
      if (a.isArb && b.isArb) return b.spread - a.spread;
      return a.hoursToEnd - b.hoursToEnd;
    });

    _spreadCache = { ts: Date.now(), data: results };
    res.json({ markets: results, updated_at: new Date().toISOString() });
  } catch (e) {
    console.error('[spread-scanner]', e.message);
    // Return stale cache on error
    if (_spreadCache.data.length) {
      return res.json({ markets: _spreadCache.data, updated_at: new Date(_spreadCache.ts).toISOString(), stale: true });
    }
    res.status(500).json({ error: 'Failed to scan spreads', markets: [] });
  }
});

// ════════════════════════════════════════════════════════════
// FEATURE 1: PORTFOLIO BACKTESTER
// ════════════════════════════════════════════════════════════
const _backtestCache = new Map(); // key: address_days → { ts, data }

app.get('/api/backtest/:address', async (req, res) => {
  try {
    const address = req.params.address;
    const days = parseInt(req.query.days) || 30;
    if (!address) return res.status(400).json({ error: 'Address required' });

    const cacheKey = `${address}_${days}`;
    const cached = _backtestCache.get(cacheKey);
    if (cached && (Date.now() - cached.ts < 10 * 60 * 1000)) {
      return res.json(cached.data);
    }

    // Get whale data from cache or fetch
    let whaleData;
    if (_whaleWatchCache && _whaleWatchCache.data) {
      whaleData = _whaleWatchCache.data;
    } else {
      whaleData = await fetchWhalePositions();
      _whaleWatchCache = { ts: Date.now(), data: whaleData };
    }

    const positions = (whaleData.whales || []).filter(p =>
      (p.proxyWallet || '').toLowerCase() === address.toLowerCase() ||
      (p.trader || '').toLowerCase() === address.toLowerCase()
    );

    if (!positions.length) {
      return res.json({ address, display_name: address, days, positions_tracked: 0, total_invested: 0, current_value: 0, pnl: 0, roi_pct: 0, best_trade: null, worst_trade: null, positions: [] });
    }

    const display_name = positions[0].trader || address;
    // Use REAL position sizes — no fake $100 allocation

    // Try to get historical prices from market_snapshots
    const cutoffDate = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
    let snapshotMap = {};
    try {
      if (pool) {
        const rows = await dbQuery(
          `SELECT market_id, yes_price, snapshot_at FROM market_snapshots
           WHERE snapshot_at >= $1 ORDER BY snapshot_at ASC`, [cutoffDate]
        );
        for (const r of rows) {
          if (!snapshotMap[r.market_id]) snapshotMap[r.market_id] = [];
          snapshotMap[r.market_id].push({ yes_price: parseFloat(r.yes_price), snapshot_at: r.snapshot_at });
        }
      } else {
        const { data } = await supabase.from('market_snapshots')
          .select('market_id, yes_price, snapshot_at')
          .gte('snapshot_at', cutoffDate)
          .order('snapshot_at', { ascending: true });
        for (const r of (data || [])) {
          if (!snapshotMap[r.market_id]) snapshotMap[r.market_id] = [];
          snapshotMap[r.market_id].push({ yes_price: parseFloat(r.yes_price), snapshot_at: r.snapshot_at });
        }
      }
    } catch (e) { console.warn('[backtest] snapshot fetch error:', e.message); }

    // Deduplicate positions by market name
    const seen = new Set();
    const uniquePositions = [];
    for (const p of positions) {
      const key = p.market || p.position;
      if (seen.has(key)) continue;
      seen.add(key);
      uniquePositions.push(p);
    }

    const backtestPositions = [];
    let total_invested = 0;
    let current_value = 0;

    for (const p of uniquePositions) {
      const market = p.market || p.position || 'Unknown';
      const currentPrice = p.current_price || 0.5;

      // Entry price: use whale's actual avg buy price if available
      // p.avg_price comes from Polymarket's avgPrice field in position data
      let entryPrice = parseFloat(p.avg_price || p.avgPrice || 0);

      // If no avg_price, try historical snapshots
      if (!entryPrice || entryPrice <= 0) {
        const marketKey = market.toLowerCase();
        for (const [mId, snaps] of Object.entries(snapshotMap)) {
          if (mId.toLowerCase().includes(marketKey.slice(0, 30)) || marketKey.includes(mId.toLowerCase().slice(0, 30))) {
            if (snaps.length > 0) { entryPrice = snaps[0].yes_price; break; }
          }
        }
      }

      // If still no entry price, estimate from cashPnl if available
      if ((!entryPrice || entryPrice <= 0) && p.pnl != null && parseFloat(p.pnl) !== 0) {
        // Back-calculate: pnl = (currentPrice - entryPrice) * shares
        // entryPrice = currentPrice - pnl/shares
        const shares = parseFloat(p.size || 0);
        if (shares > 0) {
          entryPrice = currentPrice - (parseFloat(p.pnl) / shares);
          if (entryPrice < 0.01) entryPrice = 0.01;
          if (entryPrice > 0.99) entryPrice = 0.99;
        }
      }

      // Last resort: use current price (shows 0 P&L — better than fake data)
      if (!entryPrice || entryPrice <= 0) entryPrice = currentPrice;

      // Use REAL position size from whale data
      const realSize = parseFloat(p.size || 0);
      const shares = realSize; // actual shares held
      const side = (p.side || '').toUpperCase();
      let posCurrentValue;
      if (side === 'YES' || side === 'Y') {
        posCurrentValue = shares * currentPrice;
      } else {
        // NO position: profit when price goes down
        posCurrentValue = shares * (1 - currentPrice);
      }

      // Use real P&L from whale data if available, otherwise calculate from price change
      const realPnl = parseFloat(p.pnl || 0);
      const posInvested = realSize * entryPrice;
      const posPnl = realPnl !== 0 ? realPnl : (posCurrentValue - posInvested);
      const posRoi = posInvested > 0 ? (posPnl / posInvested) * 100 : 0;

      total_invested += posInvested;
      current_value += posCurrentValue;

      backtestPositions.push({
        market,
        side: p.side,
        entry_price: Math.round(entryPrice * 10000) / 10000,
        current_price: Math.round(currentPrice * 10000) / 10000,
        pnl: Math.round(posPnl * 100) / 100,
        roi: Math.round(posRoi * 100) / 100
      });
    }

    const pnl = current_value - total_invested;
    const roi_pct = total_invested > 0 ? Math.round((pnl / total_invested) * 10000) / 100 : 0;

    // Find best and worst trades
    let best_trade = null, worst_trade = null;
    for (const pos of backtestPositions) {
      if (!best_trade || pos.pnl > best_trade.pnl) best_trade = { market: pos.market, pnl: pos.pnl };
      if (!worst_trade || pos.pnl < worst_trade.pnl) worst_trade = { market: pos.market, pnl: pos.pnl };
    }

    const result = {
      address,
      display_name,
      days,
      positions_tracked: backtestPositions.length,
      total_invested: Math.round(total_invested * 100) / 100,
      current_value: Math.round(current_value * 100) / 100,
      pnl: Math.round(pnl * 100) / 100,
      roi_pct,
      best_trade,
      worst_trade,
      positions: backtestPositions
    };

    _backtestCache.set(cacheKey, { ts: Date.now(), data: result });
    res.json(result);
  } catch (err) {
    console.error('[backtest]', err.message);
    res.status(500).json({ error: 'Backtest failed', detail: err.message });
  }
});

// ════════════════════════════════════════════════════════════
// FEATURE 2: LIVE TRADING FEED
// ════════════════════════════════════════════════════════════
let _liveFeedCache = null;

app.get('/api/live-feed', async (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit) || 20, 50);

    // Check cache (30 second TTL)
    if (_liveFeedCache && (Date.now() - _liveFeedCache.ts < 30 * 1000)) {
      return res.json({ trades: _liveFeedCache.data.slice(0, limit), updated_at: _liveFeedCache.updated_at });
    }

    const trades = [];

    // 1. Fetch REAL trades from Polymarket data API
    try {
      const fetch = _nodeFetch;
      const tradeRes = await fetch('https://data-api.polymarket.com/trades?limit=50', {
        headers: { 'Accept': 'application/json' },
        signal: AbortSignal.timeout(8000)
      });
      if (tradeRes.ok) {
        const rawTrades = await tradeRes.json();
        if (Array.isArray(rawTrades)) {
          for (const t of rawTrades) {
            const size = parseFloat(t.size || 0);
            if (size <= 500) continue; // Filter dust trades
            trades.push({
              type: 'trade',
              trader: t.pseudonym || (t.proxyWallet ? t.proxyWallet.slice(0, 8) : 'Unknown'),
              side: t.outcome || t.side || 'YES',
              market: t.title || 'Unknown',
              size: size,
              price: parseFloat(t.price || 0),
              timestamp: t.timestamp ? new Date(t.timestamp * 1000).toISOString() : new Date().toISOString(),
              url: 'https://polymarket.com/event/' + (t.eventSlug || t.slug || ''),
              icon: t.icon || null,
              tx: t.transactionHash || null,
              is_whale: false
            });
          }
        }
      }
    } catch (e) {
      console.warn('[live-feed] Polymarket trades API error:', e.message);
    }

    // 2. Merge whale trades from _whaleTradeStream
    if (_whaleTradeStream && _whaleTradeStream.length > 0) {
      for (const wt of _whaleTradeStream) {
        // Avoid duplicates by tx hash or market+trader combo
        if (wt.tx && trades.some(t => t.tx === wt.tx)) continue;
        if (trades.some(t => t.market === wt.question && t.trader === wt.trader_name)) continue;
        trades.push({
          type: 'trade',
          trader: wt.trader_name || wt.pseudonym || 'Whale',
          side: wt.side || 'YES',
          market: wt.question || 'Unknown',
          size: wt.size || 0,
          price: wt.price || 0,
          timestamp: wt.ts || new Date().toISOString(),
          url: wt.url || 'https://polymarket.com',
          icon: wt.icon || null,
          tx: wt.tx || null,
          is_whale: true
        });
      }
    }

    // Sort by timestamp descending
    trades.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

    const now = new Date().toISOString();
    _liveFeedCache = { ts: Date.now(), data: trades, updated_at: now };
    res.json({ trades: trades.slice(0, limit), updated_at: now });
  } catch (err) {
    console.error('[live-feed]', err.message);
    if (_liveFeedCache) return res.json({ trades: _liveFeedCache.data.slice(0, 20), updated_at: _liveFeedCache.updated_at });
    res.status(500).json({ error: 'Live feed failed', detail: err.message });
  }
});

// ── Market trades for a specific conditionId ──
let _marketTradesCache = {};

app.get('/api/market-trades/:conditionId', async (req, res) => {
  try {
    const conditionId = req.params.conditionId;
    if (!conditionId) return res.status(400).json({ error: 'conditionId required' });

    // Check cache (60 second TTL)
    const cached = _marketTradesCache[conditionId];
    if (cached && (Date.now() - cached.ts < 60 * 1000)) {
      return res.json({ trades: cached.data, updated_at: cached.updated_at });
    }

    const trades = [];
    try {
      const fetch = _nodeFetch;
      const tradeRes = await fetch(`https://data-api.polymarket.com/trades?market=${encodeURIComponent(conditionId)}&limit=50`, {
        headers: { 'Accept': 'application/json' },
        signal: AbortSignal.timeout(8000)
      });
      if (tradeRes.ok) {
        const rawTrades = await tradeRes.json();
        if (Array.isArray(rawTrades)) {
          for (const t of rawTrades) {
            trades.push({
              type: 'trade',
              trader: t.pseudonym || (t.proxyWallet ? t.proxyWallet.slice(0, 8) : 'Unknown'),
              side: t.outcome || t.side || 'YES',
              market: t.title || 'Unknown',
              size: parseFloat(t.size || 0),
              price: parseFloat(t.price || 0),
              timestamp: t.timestamp ? new Date(t.timestamp * 1000).toISOString() : new Date().toISOString(),
              url: 'https://polymarket.com/event/' + (t.eventSlug || t.slug || ''),
              icon: t.icon || null,
              tx: t.transactionHash || null
            });
          }
        }
      }
    } catch (e) {
      console.warn('[market-trades] Polymarket API error:', e.message);
    }

    trades.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
    const now = new Date().toISOString();
    _marketTradesCache[conditionId] = { ts: Date.now(), data: trades, updated_at: now };

    // Evict old cache entries (keep max 50 markets cached)
    const cacheKeys = Object.keys(_marketTradesCache);
    if (cacheKeys.length > 50) {
      const oldest = cacheKeys.sort((a, b) => _marketTradesCache[a].ts - _marketTradesCache[b].ts);
      for (let i = 0; i < oldest.length - 50; i++) delete _marketTradesCache[oldest[i]];
    }

    res.json({ trades, updated_at: now });
  } catch (err) {
    console.error('[market-trades]', err.message);
    res.status(500).json({ error: 'Market trades failed', detail: err.message });
  }
});

