// Run copy bot migrations on startup
(async () => {
  if (!pool) return;
  try {
    await dbQuery(`
      CREATE TABLE IF NOT EXISTS copy_bot_subscriptions (
        id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
        user_id UUID NOT NULL,
        whale_address TEXT NOT NULL,
        whale_name TEXT,
        allocation NUMERIC(12,2) DEFAULT 100,
        active BOOLEAN DEFAULT true,
        notify_only BOOLEAN DEFAULT true,
        created_at TIMESTAMPTZ DEFAULT NOW(),
        UNIQUE(user_id, whale_address)
      )
    `);
    await dbQuery(`
      CREATE TABLE IF NOT EXISTS copy_bot_trades (
        id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
        subscription_id UUID NOT NULL,
        user_id UUID NOT NULL,
        whale_address TEXT NOT NULL,
        market TEXT,
        side TEXT,
        size NUMERIC(12,2),
        price NUMERIC(6,4),
        status TEXT DEFAULT 'pending',
        order_id TEXT,
        created_at TIMESTAMPTZ DEFAULT NOW()
      )
    `);
    console.log('[copy-bot] Tables ensured');
  } catch (e) {
    console.warn('[copy-bot] Migration skipped (table may already exist):', e.message?.slice(0, 80));
  }
})();

// POST /api/copy-bot/subscribe — subscribe to copy a whale
app.post('/api/copy-bot/subscribe', requireAuth, async (req, res) => {
  try {
    const { whale_address, whale_name, allocation_per_trade, notify_only } = req.body;
    if (!whale_address) return res.status(400).json({ error: 'whale_address required' });
    const alloc = parseFloat(allocation_per_trade) || 100;
    const notifyFlag = notify_only !== false; // default true

    if (pool) {
      const rows = await dbQuery(
        `INSERT INTO copy_bot_subscriptions (user_id, whale_address, whale_name, allocation, notify_only)
         VALUES ($1, $2, $3, $4, $5)
         ON CONFLICT (user_id, whale_address) DO UPDATE SET
           allocation = EXCLUDED.allocation,
           whale_name = COALESCE(EXCLUDED.whale_name, copy_bot_subscriptions.whale_name),
           notify_only = EXCLUDED.notify_only,
           active = true
         RETURNING id`,
        [req.userId, whale_address, whale_name || null, alloc, notifyFlag]
      );
      return res.json({ subscription_id: rows[0]?.id, whale_address, allocation: alloc, notify_only: notifyFlag });
    } else {
      const { data, error } = await supabase.from('copy_bot_subscriptions')
        .upsert({
          user_id: req.userId,
          whale_address,
          whale_name: whale_name || null,
          allocation: alloc,
          notify_only: notifyFlag,
          active: true
        }, { onConflict: 'user_id,whale_address' })
        .select('id')
        .single();
      if (error) throw error;
      return res.json({ subscription_id: data?.id, whale_address, allocation: alloc, notify_only: notifyFlag });
    }
  } catch (err) {
    console.error('[copy-bot subscribe]', err.message);
    res.status(500).json({ error: 'Failed to subscribe', detail: err.message });
  }
});

// GET /api/copy-bot/subscriptions — list user's active copy subscriptions
app.get('/api/copy-bot/subscriptions', requireAuth, async (req, res) => {
  try {
    let subs = [];
    if (pool) {
      subs = await dbQuery(
        `SELECT s.id, s.whale_address, s.whale_name, s.allocation, s.active, s.notify_only, s.created_at,
                COUNT(t.id) AS trades_copied,
                COALESCE(SUM(CASE WHEN t.status = 'filled' THEN t.size ELSE 0 END), 0) AS total_pnl
         FROM copy_bot_subscriptions s
         LEFT JOIN copy_bot_trades t ON t.subscription_id = s.id
         WHERE s.user_id = $1 AND s.active = true
         GROUP BY s.id
         ORDER BY s.created_at DESC`,
        [req.userId]
      );
    } else {
      const { data } = await supabase.from('copy_bot_subscriptions')
        .select('*')
        .eq('user_id', req.userId)
        .eq('active', true)
        .order('created_at', { ascending: false });
      subs = data || [];
    }
    res.json({ subscriptions: subs });
  } catch (err) {
    console.error('[copy-bot subscriptions]', err.message);
    res.status(500).json({ error: 'Failed to fetch subscriptions' });
  }
});

// DELETE /api/copy-bot/:id — cancel subscription
app.delete('/api/copy-bot/:id', requireAuth, async (req, res) => {
  try {
    const subId = req.params.id;
    if (pool) {
      await dbQuery(
        'UPDATE copy_bot_subscriptions SET active = false WHERE id = $1 AND user_id = $2',
        [subId, req.userId]
      );
    } else {
      await supabase.from('copy_bot_subscriptions')
        .update({ active: false })
        .eq('id', subId)
        .eq('user_id', req.userId);
    }
    res.json({ success: true });
  } catch (err) {
    console.error('[copy-bot delete]', err.message);
    res.status(500).json({ error: 'Failed to cancel subscription' });
  }
});

// GET /api/copy-bot/history — all copied trades history
app.get('/api/copy-bot/history', requireAuth, async (req, res) => {
  try {
    let trades = [];
    if (pool) {
      trades = await dbQuery(
        `SELECT t.*, s.whale_name FROM copy_bot_trades t
         JOIN copy_bot_subscriptions s ON s.id = t.subscription_id
         WHERE t.user_id = $1
         ORDER BY t.created_at DESC LIMIT 100`,
        [req.userId]
      );
    } else {
      const { data } = await supabase.from('copy_bot_trades')
        .select('*')
        .eq('user_id', req.userId)
        .order('created_at', { ascending: false })
        .limit(100);
      trades = data || [];
    }
    res.json({ trades });
  } catch (err) {
    console.error('[copy-bot history]', err.message);
    res.status(500).json({ error: 'Failed to fetch trade history' });
  }
});

// ════════════════════════════════════════════════════════════
// CONSISTENT TRADERS — best weekly performers with consistency scoring
// ════════════════════════════════════════════════════════════
let _consistentTradersCache = null; // { ts, data }

async function fetchConsistentTraders() {
  // Fetch leaderboard for week AND day windows in parallel
  const [weekRes, dayRes, allRes] = await Promise.allSettled([
    fetch('https://data-api.polymarket.com/v1/leaderboard?limit=50&window=week', { headers: { Accept: 'application/json' }, signal: AbortSignal.timeout(8000) }),
    fetch('https://data-api.polymarket.com/v1/leaderboard?limit=50&window=day', { headers: { Accept: 'application/json' }, signal: AbortSignal.timeout(8000) }),
    fetch('https://data-api.polymarket.com/v1/leaderboard?limit=50&window=all', { headers: { Accept: 'application/json' }, signal: AbortSignal.timeout(8000) }),
  ]);

  let weekTraders = [];
  let dayTraders = [];
  let allTraders = [];

  if (weekRes.status === 'fulfilled' && weekRes.value.ok) {
    weekTraders = await weekRes.value.json();
  }
  if (dayRes.status === 'fulfilled' && dayRes.value.ok) {
    dayTraders = await dayRes.value.json();
  }
  if (allRes.status === 'fulfilled' && allRes.value.ok) {
    allTraders = await allRes.value.json();
  }

  if (!Array.isArray(weekTraders) || weekTraders.length === 0) {
    throw new Error('Could not fetch weekly leaderboard');
  }

  // Build day PnL lookup by address
  const dayPnlMap = {};
  (Array.isArray(dayTraders) ? dayTraders : []).forEach(t => {
    const addr = t.proxyWallet || t.proxy_wallet || t.address || '';
    if (addr) dayPnlMap[addr.toLowerCase()] = parseFloat(t.pnl) || 0;
  });

  // Build all-time lookup
  const allTimeMap = {};
  (Array.isArray(allTraders) ? allTraders : []).forEach(t => {
    const addr = t.proxyWallet || t.proxy_wallet || t.address || '';
    if (addr) allTimeMap[addr.toLowerCase()] = {
      pnl: parseFloat(t.pnl) || 0,
      vol: parseFloat(t.vol) || parseFloat(t.volume) || 0,
    };
  });

  // Score each weekly trader
  const scored = weekTraders.map(t => {
    const address = t.proxyWallet || t.proxy_wallet || t.address || '';
    const addrLower = address.toLowerCase();
    const weekPnl = parseFloat(t.pnl) || 0;
    const vol = parseFloat(t.vol) || parseFloat(t.volume) || 0;
    const dayPnl = dayPnlMap[addrLower] || 0;
    const allData = allTimeMap[addrLower] || { pnl: weekPnl, vol };
    const allTimePnl = allData.pnl;
    const totalVol = Math.max(allData.vol, vol);
    const roi = totalVol > 0 ? allTimePnl / totalVol : 0;

    // Estimate streak: if all-time PnL positive and weekly avg positive, estimate weeks profitable
    const weeklyAvg = weekPnl || 1;
    const streakEstimate = allTimePnl > 0 && weekPnl > 0 ? Math.max(1, Math.round(allTimePnl / Math.abs(weeklyAvg))) : (weekPnl > 0 ? 1 : 0);

    // Consistency score formula
    const consistencyScore = Math.min(100, Math.round(
      (allTimePnl > 0 ? 30 : 0) +
      (weekPnl > 0 ? 25 : 0) +
      (dayPnl > 0 ? 15 : 0) +
      Math.min(20, Math.log10(Math.max(1, totalVol)) * 3) +
      (roi > 0.1 ? 10 : roi > 0 ? 5 : 0)
    ));

    return {
      address,
      display_name: (() => { const n = t.userName || t.username || t.name || ''; return (!n || /^0x[0-9a-fA-F]{6,}/.test(n)) ? getWhaleNickname(address || n || `trader_${addrLower}`) : n; })(),
      consistency_score: consistencyScore,
      pnl_day: Math.round(dayPnl),
      pnl_week: Math.round(weekPnl),
      pnl_all_time: Math.round(allTimePnl),
      volume: Math.round(totalVol),
      roi: Math.round(roi * 10000) / 100, // percent with 2 decimals
      streak_estimate: Math.min(streakEstimate, 52),
      platforms: ['POLY'],
    };
  });

  // Sort by consistency score desc, then by weekly PnL
  scored.sort((a, b) => b.consistency_score - a.consistency_score || b.pnl_week - a.pnl_week);

  // Top 20 with ranks
  return scored.slice(0, 20).map((t, i) => ({ rank: i + 1, ...t }));
}

app.get('/api/consistent-traders', async (req, res) => {
  try {
    // 15 min cache
    if (_consistentTradersCache && (Date.now() - _consistentTradersCache.ts < 15 * 60 * 1000)) {
      return res.json(_consistentTradersCache.data);
    }
    const traders = await fetchConsistentTraders();
    _consistentTradersCache = { ts: Date.now(), data: traders };
    res.json(traders);
  } catch (err) {
    console.error('[consistent-traders]', err.message);
    if (_consistentTradersCache) return res.json(_consistentTradersCache.data);
    res.status(500).json({ error: 'Failed to fetch consistent traders', detail: err.message });
  }
});

