// Expiry countdown tweet — 3pm UTC (10am ET) — check for markets expiring today that are still contested
cron.schedule('0 15 * * *', safeCron('expiryTweet', async () => {
  try {
    const screenerRes = await fetch('https://gamma-api.polymarket.com/markets?closed=false&limit=100&order=volume&ascending=false', {
      headers: { Accept: 'application/json', 'User-Agent': 'Hyperflex/1.0' },
      signal: AbortSignal.timeout(10000)
    });
    if (!screenerRes.ok) return;
    const markets = await screenerRes.json();
    const today = new Date();
    const tomorrow = new Date(today); tomorrow.setDate(tomorrow.getDate() + 1);
    const expiringToday = (Array.isArray(markets) ? markets : []).filter(m => {
      if (m.closed) return false;
      const end = new Date(m.endDate || m.end_date_iso || '');
      if (isNaN(end.getTime())) return false;
      if (end > tomorrow) return false;
      let yesPct = null;
      try { if (m.outcomePrices) yesPct = Math.round(JSON.parse(m.outcomePrices)[0] * 100); } catch {}
      return yesPct != null && yesPct >= 20 && yesPct <= 80;
    }).sort((a, b) => (parseFloat(b.volume) || 0) - (parseFloat(a.volume) || 0));
    if (expiringToday.length > 0) {
      const top = expiringToday[0];
      let yesPct = null;
      try { if (top.outcomePrices) yesPct = Math.round(JSON.parse(top.outcomePrices)[0] * 100); } catch {}
      tweetExpiryAlert({ question: top.question, yes_price: yesPct / 100, volume: parseFloat(top.volume) || 0 }).catch(() => {});
    }
  } catch(e) { console.warn('[expiry-tweet]', e.message); }
}));

// ══════════════════════════════════════════════════════════════════════
// REPLY-TO-ENGAGEMENT BOT — find prediction market tweets and reply with data
// ══════════════════════════════════════════════════════════════════════
const _replyLog = [];
const _replyDraftQueue = [];
let _replyDraftId = 0;

async function replyToTweet(tweetId, text) {
  const url = 'https://api.x.com/2/tweets';
  const body = JSON.stringify({ text, reply: { in_reply_to_tweet_id: tweetId } });
  const auth = _xOAuthSign('POST', url, {});
  if (!auth) throw new Error('X API keys not configured');
  const res = await fetch(url, { method: 'POST', headers: { 'Authorization': auth, 'Content-Type': 'application/json' }, body });
  const data = await res.json();
  if (!res.ok) throw new Error(`X API ${res.status}: ${JSON.stringify(data)}`);
  console.log('[reply-bot] Replied to', tweetId);
  return data;
}

async function searchAndDraftReplies() {
  const bearer = process.env.X_BEARER_TOKEN;
  // Don't bail if no bearer — we can use OAuth1 as fallback
  if (!bearer && !_xOAuthSign) return;
  try {
    const queries = [
      'polymarket odds -is:retweet -from:HyperFlexapp',
      'kalshi prediction -is:retweet -from:HyperFlexapp',
      '"prediction market" whale -is:retweet -from:HyperFlexapp',
    ];
    const query = queries[Math.floor(Date.now() / 3600000) % queries.length];
    const searchUrl = `https://api.x.com/2/tweets/search/recent?query=${encodeURIComponent(query)}&max_results=10&tweet.fields=public_metrics,author_id,created_at,reply_settings`;
    // Use Bearer token if available, otherwise fall back to OAuth1
    const authHeader = bearer ? `Bearer ${bearer}` : _xOAuthSign('GET', searchUrl, {});
    if (!authHeader) { console.warn('[reply-bot] No auth available'); return; }
    const res = await fetch(searchUrl, { headers: { 'Authorization': authHeader }, signal: AbortSignal.timeout(10000) });
    if (!res.ok) { console.warn('[reply-bot] Search failed:', res.status); return; }
    const data = await res.json();
    const tweets = data.data || [];
    if (!tweets.length) return;
    const worthy = tweets.filter(t => {
      const m = t.public_metrics || {};
      // Skip tweets that restrict replies (only mentioned users, only followers, etc)
      if (t.reply_settings && t.reply_settings !== 'everyone') return false;
      return ((m.like_count || 0) + (m.retweet_count || 0) * 3 + (m.reply_count || 0) * 2) >= 1 && !_replyLog.includes(t.id);
    });
    if (!worthy.length) return;
    const target = worthy.sort((a, b) => {
      const aE = (a.public_metrics?.like_count || 0) + (a.public_metrics?.retweet_count || 0) * 3;
      const bE = (b.public_metrics?.like_count || 0) + (b.public_metrics?.retweet_count || 0) * 3;
      return bE - aE;
    })[0];

    let dataPoint = '';
    if (_whaleIndexCache && _whaleIndexCache.data && _whaleIndexCache.data.picks) {
      const tLower = (target.text || '').toLowerCase();
      const match = _whaleIndexCache.data.picks.find(p => {
        if ((p.total_capital || 0) < 50000) return false; // Skip low-capital markets
        if ((p.whale_count || 0) < 2) return false; // Need real whale consensus
        const mWords = (p.market || '').toLowerCase().split(/\s+/).filter(w => w.length > 4);
        return mWords.some(w => tLower.includes(w));
      });
      if (match) {
        const cap = match.total_capital >= 1000000 ? '$' + (match.total_capital/1000000).toFixed(1) + 'M' : '$' + Math.round(match.total_capital/1000) + 'K';
        dataPoint = `Market: "${match.market}". ${match.whale_count} whale wallets with ${cap} total capital. ${match.consensus_pct}% consensus on ${match.consensus_side}.`;
      }
    }
    if (!dataPoint && _screenerCache && _screenerCache.data) {
      const tLower = (target.text || '').toLowerCase();
      const match = _screenerCache.data.find(m => {
        if ((m.volume || 0) < 50000) return false; // Skip low-volume markets ($50K+ only)
        const mWords = (m.question || '').toLowerCase().split(/\s+/).filter(w => w.length > 4);
        return mWords.some(w => tLower.includes(w));
      });
      if (match) {
        const vol = match.volume >= 1000000 ? '$' + (match.volume/1000000).toFixed(1) + 'M' : '$' + Math.round(match.volume/1000) + 'K';
        const pct = match.yes_price != null ? Math.round(match.yes_price * 100) : null;
        dataPoint = pct ? `Market: "${match.question}". Currently at ${pct}% YES with ${vol} volume.` : `Market: "${match.question}". ${vol} volume.`;
      }
    }
    if (!dataPoint) {
      // Skip this tweet — no relevant data to add
      console.log(`[reply-bot] Skipping tweet ${target.id} — no matching market data`);
      return;
    }

    const anthropic = new Anthropic();
    const replyRes = await anthropic.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 200,
      system: `You write tweets for a prediction markets account. Rules:
1. ALWAYS name the specific market/question (e.g. "Will Bitcoin hit $100K by June?" not "the major contract")
2. ALWAYS include the exact odds number and dollar amount from your data
3. Sound like a sharp trader dropping alpha, not a news anchor
4. 1-2 punchy sentences max
5. NEVER say "Check out", never mention any account name, no hashtags, no emojis, no links
6. Under 240 chars
7. Output ONLY the tweet text, nothing else`,
      messages: [{ role: 'user', content: `Trending take on X:\n"${(target.text||'').substring(0, 300)}"\n\nYour data: ${dataPoint}\n\nWrite a standalone tweet that names the specific market and uses the exact numbers from your data:` }]
    });
    let reply = (replyRes.content[0]?.text || '').trim().replace(/^["']|["']$/g, '');
    if (reply.length > 200) reply = reply.substring(0, reply.lastIndexOf(' ', 200)) || reply.substring(0, 200);

    // Text-only tweets until we have proper market card images
    let postResult = null;
    let postType = 'standalone';
    const mediaId = null;

    try {
      // Try quote tweet first (more engagement), fall back to standalone
      const tweetUrl = 'https://api.x.com/2/tweets';
      const quotePayload = { text: reply, quote_tweet_id: target.id };
      if (mediaId) quotePayload.media = { media_ids: [mediaId] };
      const quoteAuth = _xOAuthSign('POST', tweetUrl, {});
      const quoteRes = await fetch(tweetUrl, {
        method: 'POST',
        headers: { 'Authorization': quoteAuth, 'Content-Type': 'application/json' },
        body: JSON.stringify(quotePayload)
      });
      const quoteData = await quoteRes.json();
      if (quoteRes.ok) {
        postResult = quoteData;
        postType = 'quote';
        console.log(`[reply-bot] QUOTE-TWEETED ${target.id}: "${reply.substring(0, 60)}..."${mediaId ? ' (with image)' : ''}`);
      } else {
        // Quote tweet failed (maybe Basic tier limitation), fall back to standalone
        console.warn(`[reply-bot] Quote tweet failed (${quoteRes.status}), falling back to standalone`);
        postResult = await postTweet(reply, mediaId);
        console.log(`[reply-bot] STANDALONE tweet inspired by ${target.id}: "${reply.substring(0, 60)}..."${mediaId ? ' (with image)' : ''}`);
      }
      _replyLog.push(target.id);
      if (_replyLog.length > 200) _replyLog.splice(0, 100);
    } catch (postErr) {
      _logError('reply-bot/post', postErr);
    }

    _replyDraftQueue.push({
      id: ++_replyDraftId, tweet_id: target.id, tweet_text: (target.text||'').substring(0, 200),
      tweet_author: target.author_id, tweet_metrics: target.public_metrics,
      reply_text: reply, data_used: dataPoint, created_at: new Date().toISOString(),
      status: postResult ? 'posted' : 'failed',
      posted_at: postResult ? new Date().toISOString() : null,
      reply_id: postResult?.data?.id || null
    });
    if (_replyDraftQueue.length > 50) _replyDraftQueue.shift();
  } catch (e) { console.warn('[reply-bot]', e.message); }
}

app.get('/api/reply-queue', (req, res) => {
  const secret = req.headers['x-admin-secret'];
  if (secret !== process.env.ADMIN_SECRET) return res.status(401).json({ error: 'Unauthorized' });
  res.json({ drafts: _replyDraftQueue.filter(r => r.status === 'draft'), posted: _replyDraftQueue.filter(r => r.status === 'posted').slice(-10), failed: _replyDraftQueue.filter(r => r.status === 'failed').slice(-10), total: _replyDraftQueue.length });
});
app.post('/api/reply-queue/:id/post', async (req, res) => {
  const secret = req.headers['x-admin-secret'];
  if (secret !== process.env.ADMIN_SECRET) return res.status(401).json({ error: 'Unauthorized' });
  const entry = _replyDraftQueue.find(r => r.id === parseInt(req.params.id) && r.status === 'draft');
  if (!entry) return res.status(404).json({ error: 'Draft not found' });
  try {
    const result = await replyToTweet(entry.tweet_id, entry.reply_text);
    entry.status = 'posted'; entry.posted_at = new Date().toISOString();
    _replyLog.push(entry.tweet_id);
    if (_replyLog.length > 200) _replyLog.splice(0, 100);
    res.json({ ok: true, reply_id: result.data?.id, text: entry.reply_text });
  } catch (e) { res.status(500).json({ error: e.message }); }
});
app.post('/api/reply-queue/:id/edit', (req, res) => {
  const secret = req.headers['x-admin-secret'];
  if (secret !== process.env.ADMIN_SECRET) return res.status(401).json({ error: 'Unauthorized' });
  const entry = _replyDraftQueue.find(r => r.id === parseInt(req.params.id) && r.status === 'draft');
  if (!entry) return res.status(404).json({ error: 'Draft not found' });
  const newText = (req.body.text || '').trim();
  if (!newText) return res.status(400).json({ error: 'Text required' });
  entry.reply_text = newText;
  res.json({ ok: true, updated: entry });
});
app.post('/api/reply-queue/:id/delete', (req, res) => {
  const secret = req.headers['x-admin-secret'];
  if (secret !== process.env.ADMIN_SECRET) return res.status(401).json({ error: 'Unauthorized' });
  const idx = _replyDraftQueue.findIndex(r => r.id === parseInt(req.params.id));
  if (idx === -1) return res.status(404).json({ error: 'Draft not found' });
  _replyDraftQueue.splice(idx, 1);
  res.json({ ok: true });
});

// Manual trigger for reply bot
app.post('/api/reply-queue/trigger', async (req, res) => {
  const secret = req.headers['x-admin-secret'];
  if (secret !== process.env.ADMIN_SECRET) return res.status(401).json({ error: 'Unauthorized' });
  try {
    await searchAndDraftReplies();
    const drafts = _replyDraftQueue.filter(r => r.status === 'draft');
    res.json({ ok: true, drafts_generated: drafts.length, drafts });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

